/* eslint-disable no-restricted-globals */
self.addEventListener('push', function (event) {
    if (event.data) {
        const data = event.data.json();
        const options = {
            body: data.body,
            icon: data.icon || '/logo192.png',
            badge: '/logo192.png',
            data: {
                url: data.data?.url || '/'
            },
            actions: [
                { action: 'open', title: 'Open App' },
                { action: 'close', title: 'Close' }
            ]
        };

        event.waitUntil(
            self.registration.showNotification(data.title, options)
        );
    }
});

self.addEventListener('notificationclick', function (event) {
    event.notification.close();

    if (event.action === 'close') return;

    event.waitUntil(
        clients.matchAll({ type: 'window' }).then(function (clientList) {
            for (let i = 0; i < clientList.length; i++) {
                let client = clientList[i];
                if (client.url === event.notification.data.url && 'focus' in client) {
                    return client.focus();
                }
            }
            if (clients.openWindow) {
                return clients.openWindow(event.notification.data.url);
            }
        })
    );
});

import React, { useState, useEffect } from 'react';
import { ArrowRightLeft, Loader2, RefreshCcw, Info, Clock, Zap, ShieldCheck } from 'lucide-react';
import { Button } from './common/Button';
import walletApi from '../api/walletApi';
import { useWallet } from '../hooks/useWallet';
import { useAuth } from '../context/AuthContext';
import toast from 'react-hot-toast';
import type { Currency } from '@/types/wallet';
import { formatCurrency } from '../lib/CurrencyFormatter';
import { motion } from 'framer-motion';
import ReCAPTCHA from 'react-google-recaptcha';
interface SwapCardProps {
    initialFromCurrency?: Currency;
    initialFromNetwork?: string;
    className?: string;
    onSuccess?: () => void;
}

export const SwapCard: React.FC<SwapCardProps> = ({ 
    initialFromCurrency = 'BTC', 
    initialFromNetwork = 'native',
    className = '', 
    onSuccess 
}) => {
    const { wallets, refresh } = useWallet();
    const { isPro, isBusiness } = useAuth();
    const [fromCurrency, setFromCurrency] = useState<Currency>(initialFromCurrency);
    const [fromNetwork, setFromNetwork] = useState<string>(initialFromNetwork);
    const [toCurrency, setToCurrency] = useState<Currency>('USD');
    const [toNetwork, setToNetwork] = useState<string>('native');
    const [amount, setAmount] = useState('');
    const [loading, setLoading] = useState(false);
    const [previewLoading, setPreviewLoading] = useState(false);
    const [slippage, setSlippage] = useState<number>(0.5); // Default 0.5%
    const [showSlippageSettings, setShowSlippageSettings] = useState(false);
    const [captchaToken, setCaptchaToken] = useState<string | null>(null);
    const [rates, setRates] = useState<Record<string, any>>({});
    const [isTouched, setIsTouched] = useState(false);
    const recaptchaRef = React.useRef<ReCAPTCHA>(null);
    
    interface Preview {
        rate: number;
        fee: number;
        feePercentage: number;
        amountOut: number;
        lockId: string;
        expiresAt: number;
        metadata?: any;
    }
    const [preview, setPreview] = useState<Preview | null>(null);
    const [timeLeft, setTimeLeft] = useState<number | null>(null);

    // Countdown logic for rate lock
    useEffect(() => {
        if (!preview) return;

        const intervalId = setInterval(() => {
            const remaining = Math.max(0, Math.ceil((preview.expiresAt - Date.now()) / 1000));
            setTimeLeft(remaining);
            
            if (remaining === 0) {
                setPreview(null);
                toast.error('Swap quote expired. Please refresh.');
            }
        }, 1000);

        return () => clearInterval(intervalId);
    }, [preview]);

    const safeWallets = Array.isArray(wallets) ? wallets : [];
    const fromWallet = safeWallets.find(w => w.currency === fromCurrency && w.network === fromNetwork);
    // Robust balance check: detect desync (available=0 but balance>0)
    const availableBalance = fromWallet 
        ? (fromWallet.available_balance > 0 ? fromWallet.available_balance : fromWallet.balance) 
        : 0;
    const isDesynced = fromWallet && Number(fromWallet.available_balance) === 0 && Number(fromWallet.balance) > 0;

    // Auto-correct invalid default selections to match real wallets
    useEffect(() => {
        if (safeWallets.length > 0) {
            const validFrom = safeWallets.some(w => w.currency === fromCurrency && w.network === fromNetwork);
            if (!validFrom) {
                const matchFromCurr = safeWallets.find(w => w.currency === fromCurrency);
                if (matchFromCurr) {
                    setFromNetwork(matchFromCurr.network);
                } else {
                    setFromCurrency(safeWallets[0].currency);
                    setFromNetwork(safeWallets[0].network);
                }
            }
            
            const validTo = safeWallets.some(w => w.currency === toCurrency && w.network === toNetwork);
            if (!validTo) {
                const possibleTos = safeWallets.filter(w => w.currency !== (validFrom ? fromCurrency : safeWallets[0]?.currency) || w.network !== (validFrom ? fromNetwork : safeWallets[0]?.network));
                if (possibleTos.length > 0) {
                    const matchToCurr = possibleTos.find(w => w.currency === toCurrency);
                    if (matchToCurr) {
                        setToNetwork(matchToCurr.network);
                    } else {
                        setToCurrency(possibleTos[0].currency);
                        setToNetwork(possibleTos[0].network);
                    }
                }
            }
        }
    }, [safeWallets, fromCurrency, fromNetwork, toCurrency, toNetwork]);

    // Fetch global rates once on mount for instant fiat estimates
    useEffect(() => {
        const fetchRates = async () => {
            try {
                const result = await walletApi.getExchangeRates();
                setRates(result);
            } catch (err) {
                console.error('Failed to fetch exchange rates:', err);
            }
        };
        fetchRates();
    }, []);

    const fetchPreview = React.useCallback(async () => {
        setPreviewLoading(true);
        try {
            const slippageDecimal = slippage / 100;
            const result = await walletApi.previewSwap(fromCurrency, toCurrency, parseFloat(amount), slippageDecimal, fromNetwork, toNetwork);
            setPreview({
                rate: Number(result.rate ?? 0),
                fee: Number(result.fee ?? 0),
                feePercentage: Number(result.feePercentage ?? 0),
                amountOut: Number(result.amountOut ?? 0),
                lockId: result.lockId,
                expiresAt: result.expiresAt,
                metadata: result.metadata
            });
        } catch (err) {
            console.error('Preview error:', err);
            setPreview(null);
        } finally {
            setPreviewLoading(false);
        }
    }, [fromCurrency, toCurrency, amount, slippage, fromNetwork, toNetwork]);

    // Auto-correct invalid default selections to match real wallets
    useEffect(() => {
        const timeoutId = setTimeout(() => {
            const numericAmount = Number(amount || 0);
            if (numericAmount > 0 && fromCurrency !== toCurrency) {
                fetchPreview();
            } else {
                setPreview(null);
            }
        }, 800); // Increased debounce to prevent rapid API calls

        return () => clearTimeout(timeoutId);
    }, [amount, fromCurrency, toCurrency, fetchPreview]);

    const handleSwapCurrencies = () => {
        const tempCurr = fromCurrency;
        const tempNet = fromNetwork;
        setFromCurrency(toCurrency);
        setFromNetwork(toNetwork);
        setToCurrency(tempCurr);
        setToNetwork(tempNet);
        setAmount('');
        setPreview(null);
        setCaptchaToken(null);
        recaptchaRef.current?.reset();
    };

    const handleMaxAmount = () => {
        const balance = Number(availableBalance || 0);
        // Floor to 8 decimals to avoid rounding up and triggering insufficiency
        const floored = Math.floor(balance * 100000000) / 100000000;
        setAmount(floored.toString());
        setIsTouched(true); // Ensure error state is updated
    };

    const handleExecuteSwap = async () => {
        const numericAmount = Number(amount || 0);
        if (numericAmount <= 0) return toast.error('Please enter a valid amount');
        
        // Inclusion fee logic: Just check if amount > balance
        if (numericAmount > Number(availableBalance || 0) + 0.0000000001) {
            return toast.error('Insufficient balance');
        }

        if (fromCurrency === toCurrency) return toast.error('Cannot swap same currency');
        if (!preview?.lockId) return toast.error('Please wait for a quote');

        // Security: Demand reCAPTCHA for financial swaps
        if (!captchaToken && import.meta.env.PROD) {
            return toast.error('Please complete the reCAPTCHA verification');
        }

        setLoading(true);
        try {
            const idempotencyKey = `swap_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`;
            const slippageDecimal = slippage / 100;
            const result = await walletApi.executeSwap(
                fromCurrency, 
                toCurrency, 
                numericAmount, 
                idempotencyKey,
                preview.lockId,
                slippageDecimal,
                fromNetwork,
                toNetwork,
                captchaToken || undefined
            );
            
            toast.success(
                `Swapped ${formatCurrency(Number(result.amountIn ?? 0), result.fromCurrency)} → ${formatCurrency(Number(result.amountOut ?? 0), result.toCurrency)}`
            );
            setAmount('');
            setPreview(null);
            setCaptchaToken(null);
            recaptchaRef.current?.reset();
            if (onSuccess) onSuccess();
            refresh();
        } catch (err: unknown) {
            toast.error(err instanceof Error ? err.message : 'Swap failed');
            setPreview(null); // Force refresh quote on failure
            setCaptchaToken(null);
            recaptchaRef.current?.reset();
        } finally {
            setLoading(false);
        }
    };

    const numericAmount = Number(amount || 0);
    const isInsufficient = numericAmount > (Number(availableBalance || 0) + 0.0000000001) && numericAmount > 0;
    const isError = isTouched && (numericAmount <= 0 || amount === '');

    // Instant USD equivalent calculation
    const fromUsdRate = rates[fromCurrency]?.['USD'] || 0;
    const fiatEquivalent = numericAmount * fromUsdRate;

    return (
        <motion.div 
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            className={`bg-gray-900 border border-gray-800 rounded-2xl p-6 shadow-xl ${className}`}
        >
            <div className="flex justify-between items-center mb-6">
                <h2 className="text-xl font-bold flex items-center gap-2">
                    <RefreshCcw size={20} className="text-purple-500" />
                    Quick Exchange
                </h2>
                <div className="bg-purple-500/10 text-purple-400 px-2 py-1 rounded text-xs font-medium border border-purple-500/20">
                    Instant
                </div>
            </div>

            <div className="space-y-4">
                {/* From Section */}
                <div className={`bg-gray-800/50 border rounded-xl p-4 transition-all duration-200 focus-within:ring-2 focus-within:bg-gray-800/80 ${
                    isError 
                        ? 'border-red-500/50 focus-within:border-red-500 ring-red-500/10' 
                        : 'border-gray-700/80 focus-within:border-purple-500/50 focus-within:ring-purple-500/10'
                }`}>
                    <div className="flex justify-between items-center mb-1">
                        <label htmlFor="swap-card-from-currency" className="text-xs text-gray-400 font-medium uppercase tracking-wider">From</label>
                        <span className={`text-xs font-medium ${isDesynced ? 'text-amber-400' : 'text-gray-400'}`}>
                            Balance: {formatCurrency(Number(availableBalance || 0), fromCurrency)}
                            {isDesynced && (
                                <span className="ml-1 inline-flex items-center" title="Balance synchronization in progress">
                                    <Info size={10} className="animate-pulse" />
                                </span>
                            )}
                        </span>
                    </div>
                    <div className="flex flex-col sm:flex-row gap-3 items-start sm:items-center">
                        <div className="flex w-full sm:w-auto items-center">
                            <select
                                id="swap-card-from-currency"
                                name="fromCurrency"
                                value={`${fromCurrency}_${fromNetwork}`}
                                onChange={(e) => {
                                    const [c, n] = e.target.value.split('_');
                                    setFromCurrency(c);
                                    setFromNetwork(n);
                                }}
                                className="bg-transparent text-xl font-bold text-white focus:outline-none cursor-pointer hover:text-purple-400 transition-colors w-full"
                            >
                                 {safeWallets.map(w => (
                                     <option key={`${w.currency}_${w.network}`} value={`${w.currency}_${w.network}`} className="bg-gray-800 text-base">
                                         {w.currency} {w.network !== 'native' ? `(${w.network})` : ''}
                                     </option>
                                 ))}
                            </select>
                        </div>
                        <div className="flex-1 w-full relative flex flex-col group/input min-w-0">
                            <div className="relative flex items-center">
                                <input
                                    id="swap-card-amount-in"
                                    name="amountIn"
                                    type="text"
                                    inputMode="decimal"
                                    value={amount}
                                    onBlur={() => setIsTouched(true)}
                                    onChange={(e) => {
                                        const val = e.target.value.replace(/[^0-9.]/g, '');
                                        // Ensure only one decimal point
                                        const parts = val.split('.');
                                        if (parts.length <= 2) {
                                            setAmount(val);
                                        }
                                    }}
                                    placeholder="0.00"
                                    className="w-full bg-transparent text-left sm:text-right text-2xl font-bold text-white placeholder-gray-600 focus:outline-none pr-12 transition-all caret-purple-500"
                                    autoComplete="off"
                                />
                                <button
                                    onClick={handleMaxAmount}
                                    className="absolute right-0 px-2 py-1 text-[10px] text-purple-400 uppercase tracking-widest font-black hover:text-white hover:bg-purple-600 transition-all bg-purple-500/10 rounded-md border border-purple-500/30 hover:shadow-[0_0_15px_rgba(147,51,234,0.3)] active:scale-95 z-10"
                                >
                                    Max
                                </button>
                            </div>
                            {/* Instant USD equivalent */}
                            {numericAmount > 0 && fromUsdRate > 0 && (
                                <motion.div 
                                    initial={{ opacity: 0, x: 10 }}
                                    animate={{ opacity: 0.6, x: 0 }}
                                    className="text-[10px] text-gray-400 text-left sm:text-right mt-0.5"
                                >
                                    ≈ {formatCurrency(fiatEquivalent, 'USD')}
                                </motion.div>
                            )}
                        </div>
                    </div>
                </div>

                {/* Swap Icon */}
                <div className="flex justify-center -my-2 relative z-10">
                    <button
                        onClick={handleSwapCurrencies}
                        className="p-2 rounded-full bg-gray-800 border border-gray-700 hover:border-purple-500 hover:bg-gray-700 transition-all shadow-lg group"
                    >
                        <ArrowRightLeft size={18} className="text-gray-400 group-hover:text-purple-400 transition-colors" />
                    </button>
                </div>

                {/* To Section */}
                <div className="bg-gray-800/50 border border-gray-700 rounded-xl p-4 transition-colors focus-within:border-purple-500/50">
                    <div className="flex justify-between items-center mb-2">
                        <label htmlFor="swap-card-to-currency" className="text-xs text-gray-400 font-medium uppercase tracking-wider">To</label>
                        {previewLoading && <Loader2 className="animate-spin text-purple-400" size={14} />}
                    </div>
                    <div className="flex gap-3 items-center">
                        <select
                            id="swap-card-to-currency"
                            name="toCurrency"
                            value={`${toCurrency}_${toNetwork}`}
                            onChange={(e) => {
                                const [c, n] = e.target.value.split('_');
                                setToCurrency(c);
                                setToNetwork(n);
                            }}
                            className="bg-transparent text-xl font-bold text-white focus:outline-none cursor-pointer hover:text-purple-400 transition-colors py-1"
                        >
                             {safeWallets.filter(w => w.currency !== fromCurrency || w.network !== fromNetwork).map(w => (
                                 <option key={`${w.currency}_${w.network}`} value={`${w.currency}_${w.network}`} className="bg-gray-800 text-base">
                                     {w.currency} {w.network !== 'native' ? `(${w.network})` : ''}
                                 </option>
                             ))}
                        </select>
                        <div className="flex-1 min-w-0">
                            <input
                                id="swap-card-amount-out"
                                name="amountOut"
                                type="text"
                                value={preview ? Number(preview.amountOut || 0).toFixed(6) : ''}
                                readOnly
                                placeholder="0.00"
                                className="w-full bg-transparent text-right text-2xl font-bold text-gray-300 placeholder-gray-600 focus:outline-none pr-2 caret-purple-500"
                            />
                        </div>
                    </div>
                </div>

                {/* Info Section */}
                <div className="min-h-[60px]">
                    {preview ? (
                        <div className="bg-purple-900/10 border border-purple-500/10 rounded-lg p-3 text-xs space-y-1">
                            <div className="flex justify-between text-gray-400">
                                <span>Rate</span>
                                <span className="text-purple-300">1 {fromCurrency} ≈ {formatCurrency(Number(preview.rate || 0), toCurrency)}</span>
                            </div>
                            <div className="flex justify-between text-gray-400">
                                <div className="flex items-center gap-1.5">
                                    <span>Processing Fee ({((Number(preview.metadata?.fee_breakdown?.rates?.total) || 0.047) * 100).toFixed(1)}%)</span>
                                    {isBusiness ? (
                                        <span className="bg-blue-500/10 text-blue-400 px-1.5 py-0.5 rounded-[4px] border border-blue-500/20 text-[9px] font-bold flex items-center gap-0.5">
                                            <ShieldCheck size={8} />
                                            50% Business Discount
                                        </span>
                                    ) : isPro ? (
                                        <span className="bg-purple-500/10 text-purple-400 px-1.5 py-0.5 rounded-[4px] border border-purple-500/20 text-[9px] font-bold flex items-center gap-0.5">
                                            <Zap size={8} />
                                            20% Pro Discount
                                        </span>
                                    ) : null}
                                </div>
                                <span>{formatCurrency(Number(preview.fee || 0), fromCurrency)}</span>
                            </div>
                            
                            {/* Detailed breakdown */}
                            <div className="grid grid-cols-2 gap-y-0.5 text-[9px] text-gray-500 pt-1 border-t border-purple-500/5">
                                <span>Platform ({(Number(preview.metadata?.fee_breakdown?.rates?.admin || 0.045) * 100).toFixed(1)}%)</span>
                                <span className="text-right">{formatCurrency(Number(preview.metadata?.fee_breakdown?.breakdown?.admin_fee || 0), fromCurrency)}</span>
                                
                                {Number(preview.metadata?.fee_breakdown?.rates?.referrer || 0) > 0 && (
                                    <>
                                        <span>Referrer ({(Number(preview.metadata?.fee_breakdown?.rates?.referrer) * 100).toFixed(1)}%)</span>
                                        <span className="text-right">{formatCurrency(Number(preview.metadata?.fee_breakdown?.breakdown?.referrer || 0), fromCurrency)}</span>
                                    </>
                                )}
                                
                                <span>Reward ({(Number(preview.metadata?.fee_breakdown?.rates?.partner || 0.001) * 100).toFixed(1)}%)</span>
                                <span className="text-right">{formatCurrency(Number(preview.metadata?.fee_breakdown?.breakdown?.partner_reward || 0), fromCurrency)}</span>
                            </div>

                            <div className="flex justify-between text-xs text-gray-500 pt-1">
                                <span>Max Slippage</span>
                                <span>{slippage}%</span>
                            </div>
                            <div className="flex justify-between items-center pt-1 border-t border-purple-500/10 mt-1">
                                <span className="text-gray-500 flex items-center gap-1">
                                    <Clock size={10} />
                                    Quote expires in
                                </span>
                                <span className={`font-mono font-bold ${Number(timeLeft || 0) < 10 ? 'text-red-400' : 'text-purple-400'}`}>
                                    {timeLeft}s
                                </span>
                            </div>
                        </div>
                    ) : (
                        <div className="flex items-center justify-center h-full text-gray-600 text-xs gap-2">
                            <Info size={14} />
                            Enter an amount to see quote
                        </div>
                    )}
                </div>

                {/* Advanced Settings (Slippage) */}
                <div className="pt-1">
                    <button 
                        onClick={() => setShowSlippageSettings(!showSlippageSettings)}
                        className="text-[10px] text-purple-400 hover:text-purple-300 flex items-center gap-1 transition-colors uppercase tracking-wider font-bold"
                    >
                        Advanced Settings {showSlippageSettings ? '▲' : '▼'}
                    </button>
                    
                    {showSlippageSettings && (
                        <motion.div 
                            initial={{ opacity: 0, height: 0 }}
                            animate={{ opacity: 1, height: 'auto' }}
                            className="mt-2 p-3 bg-gray-800/50 rounded-lg border border-gray-700/50"
                        >
                            <div className="text-[10px] text-gray-400 mb-2 uppercase tracking-wide">Slippage Tolerance</div>
                            <div className="flex gap-2">
                                {[0.1, 0.5, 1.0].map((val) => (
                                    <button
                                        key={val}
                                        onClick={() => setSlippage(val)}
                                        className={`px-2 py-1 text-xs rounded transition-colors font-medium ${
                                            slippage === val 
                                                ? 'bg-purple-600 text-white shadow-lg shadow-purple-500/20' 
                                                : 'bg-gray-800 text-gray-400 hover:bg-gray-700 border border-gray-700'
                                        }`}
                                    >
                                        {val}%
                                    </button>
                                ))}
                                <div className="flex-1 relative">
                                    <input
                                        type="number"
                                        value={slippage}
                                        onChange={(e) => setSlippage(parseFloat(e.target.value) || 0)}
                                        step="0.1"
                                        className="w-full bg-gray-800 border border-gray-700 rounded px-2 py-1 text-xs text-right text-white focus:outline-none focus:border-purple-500 transition-colors"
                                    />
                                    <span className="absolute right-2 top-1.5 text-[10px] text-gray-500">%</span>
                                </div>
                            </div>
                        </motion.div>
                    )}
                </div>

                {/* reCAPTCHA for Financial Security */}
                {preview && (
                    <div className="flex justify-center p-2 bg-gray-800/30 rounded-xl border border-gray-800">
                        <ReCAPTCHA
                            ref={recaptchaRef}
                            sitekey={import.meta.env.VITE_RECAPTCHA_SITE_KEY || '6LeIxAcTAAAAAJcZVRqyHh71UMIEGNQ_MXjiZKhI'} // Generic test key for dev
                            onChange={(token) => setCaptchaToken(token)}
                            theme="dark"
                        />
                    </div>
                )}

                <Button
                    onClick={handleExecuteSwap}
                    disabled={loading || !preview || (!captchaToken && import.meta.env.PROD) || (timeLeft !== null && timeLeft <= 0)}
                    className="w-full h-12 text-base font-bold bg-gradient-to-r from-purple-600 to-indigo-600 hover:from-purple-500 hover:to-indigo-500 border-none shadow-lg shadow-purple-500/20"
                >
                    {loading ? (
                        <Loader2 className="animate-spin" size={20} />
                    ) : (
                        `Exchange ${fromCurrency} → ${toCurrency}`
                    )}
                </Button>
                
                {isInsufficient && (
                    <p className="text-red-400 text-xs text-center font-medium animate-pulse">Insufficient {fromCurrency} balance</p>
                )}
                {isError && (
                    <p className="text-red-400 text-[10px] text-center font-medium">Please enter a valid amount greater than 0</p>
                )}
            </div>
        </motion.div>
    );
};

import React, { useEffect, useRef, useState, useMemo, useCallback } from 'react';
import { AnimatePresence } from 'framer-motion';
import { useChat } from '../../context/ChatContext';
import { usePresence } from '../../context/PresenceContext';
import { formatDistanceToNow } from 'date-fns';
import { useAuth } from '../../context/AuthContext';
import SecureImage from '../common/SecureImage';
import { Send, Languages, Flag, Phone, Video, Plus, Paperclip, Smile, Search, MoreHorizontal, Check, CheckCheck, Loader2, ArrowDown, Mic, ArrowLeft, Maximize, Trash2, Share2, X, Copy } from 'lucide-react';
import { useWebRTC } from '../../context/WebRTCContext';
import { MediaUpload } from './MediaUpload';
import { VoiceRecorder } from './VoiceRecorder';
import { AudioPlayer } from './AudioPlayer';
import { API_URL } from '../../lib/api';
import { supabase } from '../../lib/supabase';
import toast from 'react-hot-toast';
import { MediaPreviewModal } from './MediaPreviewModal';
import { MentionSuggestions } from './MentionSuggestions';
import { ForwardMessageModal } from './ForwardMessageModal';

import { ConfirmationModal } from '../common/ConfirmationModal';
import { applyAutoCorrect } from '../../utils/textUtils';
import { UserBadge } from '../common/UserBadge';

const ChatWindow: React.FC = () => {
    const { 
        activeConversationId, setActiveConversationId, messages, sendMessage, loading, 
        conversations, acceptConversation, deleteConversation, deleteMessage, editMessage,
        muteConversation, clearChatHistory, loadMoreMessages, hasMore,
        sendTypingStatus, typingUsers, sendMessageToConversation 
    } = useChat();
    const { isUserOnline, getUserLastSeen } = usePresence();
    const { user, profile, session } = useAuth();
    const { startCall } = useWebRTC();

    // ── WhatsApp-Style Selection System ──────────────────────
    const [selectedMessages, setSelectedMessages] = useState<Set<string>>(new Set());
    const longPressTimerRef = useRef<any>(null);
    const longPressTriggeredRef = useRef(false);
    const isSelectionMode = selectedMessages.size > 0;

    // Forward modal state
    const [forwardModal, setForwardModal] = useState<{
        isOpen: boolean;
        messages: { id: string; content: string; type: string }[];
    }>({ isOpen: false, messages: [] });

    // Editing state
    const [editingMessageId, setEditingMessageId] = useState<string | null>(null);

    const toggleMessageSelection = (msgId: string) => {
        setSelectedMessages(prev => {
            const next = new Set(prev);
            if (next.has(msgId)) {
                next.delete(msgId);
            } else {
                next.add(msgId);
            }
            return next;
        });
    };

    const clearSelection = () => {
        setSelectedMessages(new Set());
    };

    const handleLongPressStart = (msgId: string) => {
        longPressTriggeredRef.current = false;
        longPressTimerRef.current = setTimeout(() => {
            longPressTriggeredRef.current = true;
            // Haptic feedback for mobile
            if (navigator.vibrate) navigator.vibrate(30);
            toggleMessageSelection(msgId);
        }, 350);
    };

    const handleLongPressEnd = () => {
        if (longPressTimerRef.current) {
            clearTimeout(longPressTimerRef.current);
            longPressTimerRef.current = null;
        }
    };

    const handleMessageClick = (msgId: string) => {
        if (longPressTriggeredRef.current) {
            longPressTriggeredRef.current = false;
            return; // was a long press, don't toggle
        }
        if (isSelectionMode) {
            toggleMessageSelection(msgId);
        }
    };

    // Copy to clipboard
    const handleCopy = async () => {
        if (selectedMessages.size === 0) return;
        const selectedMsgs = currentMessages
            .filter(m => selectedMessages.has(m.id))
            .sort((a, b) => new Date(a.created_at).getTime() - new Date(b.created_at).getTime())
            .map(m => m.content)
            .join('\n');
        
        try {
            await navigator.clipboard.writeText(selectedMsgs);
            toast.success(selectedMessages.size > 1 ? 'Messages copied' : 'Message copied');
            clearSelection();
        } catch (err) {
            toast.error('Failed to copy to clipboard');
        }
    };

    // Cleanup long press timer on unmount
    useEffect(() => {
        return () => {
            if (longPressTimerRef.current) clearTimeout(longPressTimerRef.current);
        };
    }, []);
    
    const [inputValue, setInputValue] = useState('');
    const [showMediaUpload, setShowMediaUpload] = useState(false);
    const [signedUrls, setSignedUrls] = useState<Record<string, string>>({});
    
    // Confirmation state
    const [confirmModal, setConfirmModal] = useState<{
        isOpen: boolean;
        type: 'message' | 'clear' | 'delete_chat';
        messageId?: string;
    }>({
        isOpen: false,
        type: 'message'
    });

    const [previewMedia, setPreviewMedia] = useState<{
        isOpen: boolean;
        url: string;
        type: 'image' | 'video';
        fileName?: string;
        isSender?: boolean;
    }>({
        isOpen: false,
        url: '',
        type: 'image'
    });
    
    const messagesEndRef = useRef<HTMLDivElement>(null);
    const scrollContainerRef = useRef<HTMLDivElement>(null);
    const [translations, setTranslations] = useState<{ [key: string]: string }>({});
    const [showOriginal, setShowOriginal] = useState<{ [key: string]: boolean }>({});
    const [isAtBottom, setIsAtBottom] = useState(true);
    
    // Search states
    const [isSearchOpen, setIsSearchOpen] = useState(false);
    const [searchQuery, setSearchQuery] = useState('');
    const [searchResults, setSearchResults] = useState<any[]>([]);
    const [isSearching, setIsSearching] = useState(false);
    const [showEmojiPicker, setShowEmojiPicker] = useState(false);
    const [isAccepting, setIsAccepting] = useState(false);
    
    // Mentions state
    const [mentionSearch, setMentionSearch] = useState('');
    const [mentionParticipants, setMentionParticipants] = useState<any[]>([]);
    const [showMentions, setShowMentions] = useState(false);
    
    const emojis = ['😀', '😂', '😍', '🙌', '🔥', '👍', '🙏', '💯', '✨', '❤️', '🎉', '😊', '✅', '🚀', '👀', '💡'];

    const preferredLanguage = profile?.preferred_language || 'en';

    const currentMessages = useMemo(() => activeConversationId ? messages[activeConversationId] || [] : [], [messages, activeConversationId]);
    const activeConversation = useMemo(() => conversations.find(c => c.id === activeConversationId), [conversations, activeConversationId]);

    const myMember = activeConversation?.members.find((m: { user_id: string; status: string }) => m.user_id === user?.id);
    const isPending = myMember?.status === 'pending';

    const otherMember = useMemo(() => {
        if (!activeConversation?.members || !user) return null;
        return activeConversation.members.find((m: any) => m.user_id !== user.id) || null;
    }, [activeConversation?.members, user, user?.id]);

    const isWaitingForOthers = myMember?.status === 'accepted' && otherMember?.status === 'pending';

    const scrollToBottom = () => {
        messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
    };

    const handleScroll = () => {
        if (!scrollContainerRef.current) return;
        const { scrollTop, scrollHeight, clientHeight } = scrollContainerRef.current;
        const reachedBottom = scrollHeight - scrollTop - clientHeight < 50;
        setIsAtBottom(reachedBottom);
    };

    useEffect(() => {
        if (isAtBottom) scrollToBottom();
    }, [currentMessages, isAtBottom]);

    useEffect(() => {
        const translateNewMessages = async () => {
            if (!activeConversationId || !preferredLanguage) return;

            const messagesToTranslate = currentMessages.filter(msg => {
                const sourceLang = msg.original_language || 'en';
                const isDifferent = sourceLang !== preferredLanguage;
                const notOwn = msg.sender_id !== user?.id;
                const notTranslated = !translations[msg.id];
                return notOwn && isDifferent && notTranslated && msg.type === 'text';
            });

            for (const msg of messagesToTranslate) {
                try {
                    setTranslations(prev => ({ ...prev, [msg.id]: 'translating...' }));
                    const response = await fetch(`${API_URL}/api/chat/translate`, {
                        method: 'POST',
                        headers: {
                            'Content-Type': 'application/json',
                            'Authorization': `Bearer ${session?.access_token}`
                        },
                        body: JSON.stringify({
                            text: msg.content,
                            targetLang: preferredLanguage,
                            sourceLang: msg.original_language
                        })
                    });

                    if (response.ok) {
                        const data = await response.json();
                        setTranslations(prev => ({ ...prev, [msg.id]: data.translation }));
                    } else {
                        setTranslations(prev => ({ ...prev, [msg.id]: '[Translation Failed]' }));
                    }
                } catch (e) {
                    setTranslations(prev => ({ ...prev, [msg.id]: '[Translation Error]' }));
                }
            }
        };

        translateNewMessages();
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [currentMessages, activeConversationId, preferredLanguage, user, session?.access_token]);

    const handleManualTranslate = async (msgId: string, content: string, sourceLang?: string) => {
        if (!preferredLanguage || !session?.access_token) return;
        
        try {
            setTranslations(prev => ({ ...prev, [msgId]: 'translating...' }));
            const response = await fetch(`${API_URL}/api/chat/translate`, {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                    'Authorization': `Bearer ${session.access_token}`
                },
                body: JSON.stringify({
                    text: content,
                    targetLang: preferredLanguage,
                    sourceLang: sourceLang
                })
            });

            if (response.ok) {
                const data = await response.json();
                setTranslations(prev => ({ ...prev, [msgId]: data.translation }));
                setShowOriginal(prev => ({ ...prev, [msgId]: false }));
            } else {
                setTranslations(prev => ({ ...prev, [msgId]: '[Translation Failed]' }));
            }
        } catch (e) {
            setTranslations(prev => ({ ...prev, [msgId]: '[Translation Error]' }));
        }
    };

    const handleReport = async (msgId: string, original: string, translated: string) => {
        try {
            await fetch(`${API_URL}/api/chat/report-translation`, {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                    'Authorization': `Bearer ${session?.access_token}`
                },
                body: JSON.stringify({
                    messageId: msgId,
                    originalText: original,
                    translatedText: translated,
                    targetLang: preferredLanguage,
                    comment: 'User reported poor translation'
                })
            });
            toast.success('Report sent. Thanks for the feedback!');
        } catch (e) {
            toast.error('Failed to send report');
        }
    };

    useEffect(() => {
        if (!searchQuery.trim() || !isSearchOpen) {
            setSearchResults([]);
            setIsSearching(false);
            return;
        }

        setIsSearching(true);
        const delayDebounce = setTimeout(async () => {
            try {
                const res = await fetch(`${API_URL}/api/chat/conversations/${activeConversationId}/search?q=${encodeURIComponent(searchQuery)}`, {
                    headers: { 'Authorization': `Bearer ${session?.access_token}` }
                });
                if (res.ok) {
                    const data = await res.json();
                    setSearchResults(data);
                }
            } catch (err) {
                console.error('Search failed:', err);
            } finally {
                setIsSearching(false);
            }
        }, 500);

        return () => clearTimeout(delayDebounce);
    }, [searchQuery, isSearchOpen, activeConversationId, session?.access_token]);

    const fetchSignedUrl = useCallback(async (path: string) => {
        if (signedUrls[path]) return signedUrls[path];
        try {
            const res = await fetch(`${API_URL}/api/media/signed-url?path=${encodeURIComponent(path)}`, {
                headers: { 'Authorization': `Bearer ${session?.access_token}` }
            });
            if (res.ok) {
                const { url } = await res.json();
                setSignedUrls(prev => ({ ...prev, [path]: url }));
                return url;
            }
        } catch (err) {
            console.error('Failed to get signed URL:', err);
        }
        return null;
    }, [signedUrls, session?.access_token]);

    const handleSend = async (e?: React.FormEvent) => {
        if (e) e.preventDefault();
        if (!inputValue.trim() || !activeConversationId) return;

        try {
            if (editingMessageId) {
                await editMessage(editingMessageId, inputValue);
                setEditingMessageId(null);
            } else {
                await sendMessage(inputValue);
            }
            setInputValue('');
            setShowMentions(false);
        } catch (err) {
            toast.error(editingMessageId ? 'Failed to edit message' : 'Failed to send message');
        }
    };

    const handleMediaUploadComplete = async (attachmentId: string, type: string, fileName: string) => {
        try {
            await sendMessage(`Shared a ${type}: ${fileName}`, type, attachmentId);
            setShowMediaUpload(false);
        } catch (err) {
            toast.error('Failed to send media message');
        }
    };

    const handleAccept = async () => {
        if (isAccepting || !activeConversationId) return;
        setIsAccepting(true);
        try {
            await acceptConversation(activeConversationId);
        } catch (err) {
            console.error('Accept failed', err);
        } finally {
            setIsAccepting(false);
        }
    };

    const [showMoreMenu, setShowMoreMenu] = useState(false);
    const [isVoiceRecording, setIsVoiceRecording] = useState(false);

    const handleClearChat = () => {
        if (!activeConversationId) return;
        setShowMoreMenu(false);
        setConfirmModal({ isOpen: true, type: 'clear' });
    };

    const handleMuteChat = async () => {
        if (!activeConversationId) return;
        setShowMoreMenu(false);
        const nextMuteStatus = !activeConversation?.is_muted;
        try {
            await muteConversation(activeConversationId, nextMuteStatus);
            toast.success(nextMuteStatus ? 'Chat muted' : 'Chat unmuted');
        } catch (err) {
            toast.error('Failed to update mute status');
        }
    };

    const handleDeleteChat = () => {
        if (!activeConversationId) return;
        setShowMoreMenu(false);
        setConfirmModal({ isOpen: true, type: 'delete_chat' });
    };

    const handleVoiceMessage = async (blob: Blob) => {
        if (!session || !activeConversationId) return;
        
        const loadingToast = toast.loading('Sending voice message...');
        try {
            const mimeType = blob.type || 'audio/webm';
            const extension = mimeType.includes('mp4') ? 'm4a' : (mimeType.includes('ogg') ? 'ogg' : 'webm');
            const fileName = `voice_${Date.now()}.${extension}`;
            const filePath = `${activeConversationId}/${fileName}`;

            // 1. Upload to Supabase Storage
            const { error: uploadError, data } = await supabase.storage
                .from('chat-media')
                .upload(filePath, blob, {
                    cacheControl: '3600',
                    upsert: false,
                    contentType: mimeType
                });

            if (uploadError) throw uploadError;

            // 2. Create Attachment Record
            const res = await fetch(`${API_URL}/api/media/attachments`, {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                    'Authorization': `Bearer ${session.access_token}`
                },
                body: JSON.stringify({
                    conversationId: activeConversationId,
                    fileName,
                    fileType: mimeType,
                    fileSize: blob.size,
                    storagePath: data.path,
                    metadata: { mimeType }
                })
            });

            if (!res.ok) throw new Error('Failed to create attachment record');
            const attachment = await res.json();

            // 3. Send Message
            await sendMessage('Sent a voice message', 'audio', attachment.id);
            
            setIsVoiceRecording(false);
            toast.success('Voice message sent', { id: loadingToast });
        } catch (err) {
            console.error('Failed to send voice message:', err);
            toast.error('Failed to send voice message', { id: loadingToast });
        }
    };

    const otherUserTitle = activeConversation?.type === 'direct' && otherMember 
        ? (otherMember.profile?.full_name || otherMember.profile?.username || 'User')
        : 'Chat';

    const otherUserAvatar = activeConversation?.type === 'direct' && otherMember
        ? otherMember.profile?.avatar_url
        : null;

    const handleCall = (type: 'voice' | 'video') => {
        if (!activeConversationId || !otherMember?.user_id) {
            toast.error('Could not find participant to call');
            return;
        }
        if (isWaitingForOthers) {
            toast.error('Waiting for participant to join the conversation');
            return;
        }
        if (!isUserOnline(otherMember.user_id)) {
            toast(`${otherUserTitle} may be away. Call will still be attempted.`, { icon: 'ℹ️', duration: 3000 });
        }
        toast.loading(`Starting ${type} call...`, { duration: 2000, id: 'call-start' });
        startCall(otherMember.user_id, activeConversationId, type, otherUserTitle, otherUserAvatar || undefined)
            .catch(() => {
                toast.error('Failed to start call. Check camera/mic permissions.');
            });
    };

    // Typing Status Debounce
    const typingTimeoutRef = useRef<any>(null);

    const handleInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const val = applyAutoCorrect(e.target.value);
        setInputValue(val);

        // Emit typing status
        sendTypingStatus(true);
        if (typingTimeoutRef.current) clearTimeout(typingTimeoutRef.current);
        typingTimeoutRef.current = setTimeout(() => {
            sendTypingStatus(false);
        }, 3000);

        // Mention detection
        const lastAtPos = val.lastIndexOf('@');
        // ... (rest of the logic)
        if (lastAtPos !== -1) {
            const query = val.substring(lastAtPos + 1).split(' ')[0];
            const beforeAt = val.substring(0, lastAtPos);
            // Show only if @ is at start or preceded by space
            if (lastAtPos === 0 || beforeAt.endsWith(' ')) {
                setMentionSearch(query);
                setShowMentions(true);
                
                // Filter current conversation members
                if (activeConversation?.members) {
                    const filtered = activeConversation.members
                        .filter((m: any) => m.user_id !== user?.id && m.profile)
                        .map((m: any) => m.profile)
                        .filter((p: any) => 
                            p.username.toLowerCase().includes(query.toLowerCase()) || 
                            p.full_name?.toLowerCase().includes(query.toLowerCase())
                        );
                    setMentionParticipants(filtered);
                }
            } else {
                setShowMentions(false);
            }
        } else {
            setShowMentions(false);
        }
    };

    const handleSelectMention = (mentionedUser: any) => {
        const lastAtPos = inputValue.lastIndexOf('@');
        const beforeAt = inputValue.substring(0, lastAtPos);
        const afterMention = inputValue.substring(lastAtPos + mentionSearch.length + 1);
        setInputValue(`${beforeAt}@${mentionedUser.username} ${afterMention}`);
        setShowMentions(false);
        sendTypingStatus(true); // Re-trigger typing
    };

    // Message Grouping Helper
    const isSameSender = (index: number) => {
        if (index === 0) return false;
        const current = currentMessages[index];
        const previous = currentMessages[index - 1];
        if (!current || !previous) return false;
        
        const timeDiff = new Date(current.created_at).getTime() - new Date(previous.created_at).getTime();
        return current.sender_id === previous.sender_id && timeDiff < 60000; // Group if within 1 minute
    };

    if (!activeConversationId) {
        return (
            <div className="flex items-center justify-center h-full text-gray-500 bg-gray-900">
                <p>Select a conversation to start chatting</p>
            </div>
        );
    }

    if (loading) {
        return (
            <div className="flex items-center justify-center h-full bg-gray-900 text-gray-400">
                <Loader2 className="w-8 h-8 animate-spin" />
            </div>
        );
    }

    return (
        <div className="flex-1 flex flex-col h-full min-h-0 bg-gray-900 text-white overflow-hidden relative max-w-[1100px] mx-auto w-full shadow-2xl border-x border-gray-800">
            {/* ── Selection Action Bar (WhatsApp-style) ── */}
            {isSelectionMode ? (
                <div className="pt-safe flex-shrink-0 border-b border-blue-500/30 bg-blue-600/10 backdrop-blur-md sticky top-0 z-10 animate-in slide-in-from-top-2 duration-200">
                    <div className="p-2 md:p-4 flex items-center justify-between gap-4 w-full">
                        <div className="flex items-center gap-3">
                            <button 
                                onClick={clearSelection}
                                className="p-2 text-gray-300 hover:text-white hover:bg-white/10 rounded-full transition-all active:scale-90"
                                aria-label="Cancel selection"
                            >
                                <X size={22} />
                            </button>
                            <span className="text-white font-bold text-base">
                                {selectedMessages.size} selected
                            </span>
                        </div>
                        <div className="flex items-center gap-1 md:gap-2">
                            <button 
                                onClick={() => {
                                    const selectedMsgs = currentMessages
                                        .filter(m => selectedMessages.has(m.id))
                                        .map(m => ({ id: m.id, content: m.content, type: m.type }));
                                    setForwardModal({ isOpen: true, messages: selectedMsgs });
                                }}
                                className="flex items-center gap-2 px-4 py-2 text-sm font-semibold text-blue-300 hover:text-blue-200 hover:bg-blue-500/15 rounded-xl transition-all active:scale-95"
                            >
                                <Share2 size={18} />
                                <span className="hidden sm:inline">Forward</span>
                            </button>
                            {selectedMessages.size === 1 && (
                                (() => {
                                    const msgId = Array.from(selectedMessages)[0];
                                    const msg = currentMessages.find(m => m.id === msgId);
                                    if (msg && msg.isOwn && msg.type === 'text') {
                                        return (
                                            <button 
                                                onClick={() => {
                                                    setEditingMessageId(msg.id);
                                                    setInputValue(msg.content || '');
                                                    clearSelection();
                                                }}
                                                className="flex items-center gap-2 px-4 py-2 text-sm font-semibold text-green-400 hover:text-green-300 hover:bg-green-500/15 rounded-xl transition-all active:scale-95"
                                            >
                                                <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M11 4H4a2 2 0 0 0-2 2v14a2 2 0 0 0 2 2h14a2 2 0 0 0 2-2v-7"></path><path d="M18.5 2.5a2.121 2.121 0 0 1 3 3L12 15l-4 1 1-4 9.5-9.5z"></path></svg>
                                                <span className="hidden sm:inline">Edit</span>
                                            </button>
                                        );
                                    }
                                    return null;
                                })()
                            )}
                            <button 
                                onClick={handleCopy}
                                className="flex items-center gap-2 px-4 py-2 text-sm font-semibold text-gray-300 hover:text-white hover:bg-white/10 rounded-xl transition-all active:scale-95"
                            >
                                <Copy size={18} />
                                <span className="hidden sm:inline">Copy</span>
                            </button>
                            <button 
                                onClick={() => {
                                    setConfirmModal({ isOpen: true, type: 'message', messageId: Array.from(selectedMessages)[0] });
                                }}
                                className="flex items-center gap-2 px-4 py-2 text-sm font-semibold text-red-400 hover:text-red-300 hover:bg-red-500/15 rounded-xl transition-all active:scale-95"
                            >
                                <Trash2 size={18} />
                                <span className="hidden sm:inline">Delete</span>
                            </button>
                        </div>
                    </div>
                </div>
            ) : (
            <div className="pt-safe flex-shrink-0 border-b border-gray-800 bg-gray-900/50 backdrop-blur-md sticky top-0 z-10">
                <div className="p-2 md:p-4 flex items-center justify-between gap-4 w-full">
                    <div className="flex items-center gap-2 md:gap-3 min-w-0 flex-1">
                        <button 
                            onClick={() => setActiveConversationId(null)}
                            className="p-1.5 -ml-1 text-gray-400 hover:text-white md:hidden"
                            aria-label="Back to conversations"
                        >
                            <ArrowLeft size={22} />
                        </button>
                        {(() => {
                            let displayName = activeConversation?.name;
                            let displayAvatar = null;
                            let otherM = null;

                            if (activeConversation?.type === 'direct') {
                                otherM = activeConversation.members.find((m: any) => m.user_id !== user?.id);
                                if (otherM && otherM.profile) {
                                    const p = otherM.profile as any;
                                    displayName = p.full_name || p.username;
                                    displayAvatar = p.avatar_url;
                                }
                            }

                            return (
                                <>
                                    <div className="w-8 h-8 md:w-10 md:h-10 rounded-full bg-gradient-to-br from-blue-500 to-indigo-600 flex items-center justify-center overflow-hidden border border-white/10 shadow-lg flex-shrink-0">
                                        {displayAvatar ? (
                                            <SecureImage src={displayAvatar} alt={displayName} className="w-full h-full object-cover" fallbackType="profile" />
                                        ) : (
                                            <span className="text-white font-bold text-base md:text-lg">
                                                {displayName?.charAt(0).toUpperCase() || '?'}
                                            </span>
                                        )}
                                    </div>
                                    <div className="min-w-0">
                                        <h2 className="font-semibold truncate max-w-[60px] xs:max-w-[100px] sm:max-w-[150px] md:max-w-[300px] text-[10px] xs:text-xs md:text-base flex items-center gap-1">
                                            {displayName || 'Chat'}
                                            {activeConversation?.type === 'direct' && otherM && (
                                                <UserBadge 
                                                    planTier={(otherM as any).profile?.plan_tier}
                                                    isVerified={(otherM as any).profile?.is_verified}
                                                />
                                            )}
                                        </h2>
                                        {activeConversationId && typingUsers[activeConversationId]?.length > 0 ? (
                                            <p className="text-[10px] text-blue-400 animate-pulse font-medium flex items-center gap-1">
                                                <span className="flex gap-0.5">
                                                    <span className="w-1.5 h-1.5 bg-blue-400 rounded-full animate-bounce"></span>
                                                    <span className="w-1.5 h-1.5 bg-blue-400 rounded-full animate-bounce [animation-delay:0.2s]"></span>
                                                    <span className="w-1.5 h-1.5 bg-blue-400 rounded-full animate-bounce [animation-delay:0.4s]"></span>
                                                </span>
                                                Typing...
                                            </p>
                                        ) : activeConversation?.type === 'direct' && otherM ? (
                                            isUserOnline(otherM.user_id) ? (
                                                <p className="text-[8px] xs:text-[10px] text-green-400 flex items-center gap-1">
                                                    <span className="w-1.5 h-1.5 rounded-full bg-green-400"></span> Online
                                                </p>
                                            ) : (
                                                <p className="text-[10px] text-gray-400 hidden sm:flex items-center gap-1">
                                                    <span className="w-1.5 h-1.5 rounded-full bg-gray-500"></span> 
                                                    {(otherM.profile as any)?.show_online_status === false ? (
                                                        'offline'
                                                    ) : (
                                                        (() => {
                                                            const ts = getUserLastSeen(otherM.user_id) || (otherM.profile as any)?.last_seen;
                                                            return ts ? `Last seen ${formatDistanceToNow(new Date(ts), { addSuffix: true })}` : 'offline';
                                                        })()
                                                    )}
                                                </p>
                                            )
                                        ) : (
                                            <p className="text-[10px] text-gray-400 hidden sm:block">Group Chat</p>
                                        )}
                                    </div>
                                </>
                            );
                        })()}
                    </div>

                    <div className="flex items-center gap-1 md:gap-3 flex-shrink-0 ml-auto">
                        {isSearchOpen ? (
                            <div className="flex-1 max-w-full md:max-w-md absolute md:relative inset-x-0 top-0 h-full bg-gray-900 md:bg-transparent px-4 md:px-0 flex items-center z-20 animate-in slide-in-from-top-4 md:slide-in-from-right-4 duration-300">
                                <Search size={16} className="absolute left-7 md:left-3 top-1/2 -translate-y-1/2 text-gray-400" />
                                <input 
                                    id="chat-search-messages"
                                    name="searchMessages"
                                    autoFocus
                                    value={searchQuery}
                                    onChange={(e) => setSearchQuery(e.target.value)}
                                    placeholder="Search..."
                                    className="w-full bg-gray-800 border border-gray-700 rounded-full py-1.5 pl-10 pr-10 text-xs focus:outline-none focus:border-blue-500"
                                />
                                <button 
                                    onClick={() => { setIsSearchOpen(false); setSearchQuery(''); }}
                                    className="absolute right-7 md:right-3 top-1/2 -translate-y-1/2 text-gray-500 hover:text-white text-[10px] font-bold"
                                >ESC</button>
                            </div>
                        ) : (
                            <button onClick={() => setIsSearchOpen(true)} className="p-2 text-gray-400 hover:text-white hover:bg-white/5 rounded-full transition-all">
                                <Search size={20} />
                            </button>
                        )}
                        {!isPending && (
                            <div className="flex items-center gap-1 md:gap-2">
                                <button onClick={() => handleCall('voice')} className="p-2 text-gray-400 hover:text-green-400 hover:bg-green-400/10 rounded-full transition-all flex-shrink-0" aria-label="Audio call">
                                    <Phone size={18} className="md:w-5 md:h-5" />
                                </button>
                                <button onClick={() => handleCall('video')} className="p-2 text-gray-400 hover:text-blue-400 hover:bg-blue-400/10 rounded-full transition-all flex-shrink-0" aria-label="Video call">
                                    <Video size={18} className="md:w-5 md:h-5" />
                                </button>
                            </div>
                        )}
                        <div className="relative">
                            <button 
                                onClick={() => setShowMoreMenu(!showMoreMenu)}
                                className={`p-2 rounded-full transition-all ${showMoreMenu ? 'bg-gray-700 text-white' : 'text-gray-400 hover:text-white hover:bg-white/5'}`}
                            >
                                <MoreHorizontal size={20} />
                            </button>
                            {showMoreMenu && (
                                <div className="absolute top-full right-0 mt-2 w-48 bg-gray-800 border border-gray-700 rounded-xl shadow-2xl z-50 p-1 animate-in zoom-in-95 duration-200">
                                    <button onClick={handleMuteChat} className="w-full text-left px-4 py-2 text-sm text-gray-300 hover:bg-gray-700 rounded-lg">{activeConversation?.is_muted ? 'Unmute Notifications' : 'Mute Notifications'}</button>
                                    <button onClick={handleClearChat} className="w-full text-left px-4 py-2 text-sm text-gray-300 hover:bg-gray-700 rounded-lg">Clear History</button>
                                    <button onClick={handleDeleteChat} className="w-full text-left px-4 py-2 text-sm text-red-400 hover:bg-red-400/10 rounded-lg">Delete Chat</button>
                                </div>
                            )}
                        </div>
                    </div>
                </div>
            </div>
            )}

            {hasMore[activeConversationId] && (
                <div className="flex justify-center py-2 bg-gray-900">
                    <button onClick={() => loadMoreMessages(activeConversationId)} className="text-xs font-medium text-blue-400 hover:text-blue-300">Load older messages</button>
                </div>
            )}

            <div 
                className="flex-1 overflow-y-auto p-2 md:p-4 space-y-3 md:space-y-4 scroll-smooth overscroll-contain transition-all"
                style={{ 
                    WebkitOverflowScrolling: 'touch',
                    paddingBottom: '100px'
                }}
                ref={scrollContainerRef}
                onScroll={handleScroll}
            >
                {isSearchOpen && searchQuery.trim() !== '' ? (
                    <div className="space-y-4">
                        <p className="text-[10px] text-gray-500 uppercase tracking-widest font-bold mb-4">
                            {isSearching ? 'Searching...' : `Search Results (${searchResults.length})`}
                        </p>
                        {searchResults.length === 0 && !isSearching && (
                            <p className="text-center text-gray-500 py-10 text-sm">No messages found matching "{searchQuery}"</p>
                        )}
                        {searchResults.map((msg) => (
                            <SearchMessageItem 
                                key={msg.id} 
                                msg={msg} 
                                isOwn={msg.sender_id === user?.id} 
                                query={searchQuery} 
                                fetchUrl={fetchSignedUrl} 
                                onPreviewMedia={(data) => setPreviewMedia({ isOpen: true, ...data })}
                            />
                        ))}
                    </div>
                ) : (
                    <>
                        {currentMessages.map((msg, index) => {
                            const isGrouped = isSameSender(index);
                            const isSelected = selectedMessages.has(msg.id);
                            return (
                                <div 
                                    key={msg.id || `msg-temp-${index}`} 
                                    className={`flex ${msg.sender_id === user?.id ? 'justify-end' : 'justify-start'} ${isGrouped ? '-mt-2 md:-mt-3' : 'mt-4'} animate-in fade-in slide-in-from-bottom-2 duration-300`}
                                    onTouchStart={() => handleLongPressStart(msg.id)}
                                    onTouchEnd={handleLongPressEnd}
                                    onTouchCancel={handleLongPressEnd}
                                    onMouseDown={() => handleLongPressStart(msg.id)}
                                    onMouseUp={handleLongPressEnd}
                                    onMouseLeave={handleLongPressEnd}
                                    onClick={() => handleMessageClick(msg.id)}
                                    style={{ userSelect: 'text', WebkitUserSelect: 'text' }}
                                >
                                    {/* Selection checkbox indicator */}
                                    {isSelectionMode && (
                                        <div className={`flex items-center mr-2 flex-shrink-0 self-center transition-all duration-200 ${msg.sender_id === user?.id ? 'order-2 ml-2 mr-0' : ''}`}>
                                            <div className={`w-5 h-5 rounded-full border-2 flex items-center justify-center transition-all duration-200 ${
                                                isSelected 
                                                    ? 'bg-blue-500 border-blue-500 scale-110' 
                                                    : 'border-gray-500 bg-transparent hover:border-gray-400'
                                            }`}>
                                                {isSelected && (
                                                    <Check size={12} className="text-white animate-in zoom-in-0 duration-150" />
                                                )}
                                            </div>
                                        </div>
                                    )}
                                    <div className={`max-w-[92%] md:max-w-[70%] ${isGrouped ? 'rounded-2xl' : (msg.sender_id === user?.id ? 'rounded-2xl rounded-br-sm' : 'rounded-2xl rounded-bl-sm')} p-3 shadow-md border ${
                                        isSelected
                                            ? 'bg-blue-600/30 border-blue-400/50 ring-1 ring-blue-500/30'
                                            : (msg.sender_id === user?.id ? 'bg-gradient-to-br from-blue-600 to-indigo-700 text-white border-blue-500/50' : 'bg-gray-800 text-gray-200 border-gray-700')
                                    } relative group transition-all duration-200 ${isSelectionMode ? 'cursor-pointer' : ''}`}>
                                        {msg.attachment && msg.type !== 'audio' && (
                                            <div className="mb-2 rounded-lg overflow-hidden border border-black/20 bg-black/10">
                                                {msg.type === 'image' ? (
                                                    <ImageWithSignedUrl 
                                                        path={msg.attachment.storage_path} 
                                                        fetchUrl={fetchSignedUrl} 
                                                        onPreview={(url) => setPreviewMedia({ isOpen: true, url, type: 'image', fileName: msg.attachment?.file_name, isSender: msg.sender_id === user?.id })}
                                                    />
                                                ) : msg.type === 'video' ? (
                                                    <VideoWithSignedUrl 
                                                        path={msg.attachment.storage_path} 
                                                        fetchUrl={fetchSignedUrl} 
                                                        onPreview={(url) => setPreviewMedia({ isOpen: true, url, type: 'video', fileName: msg.attachment?.file_name, isSender: msg.sender_id === user?.id })}
                                                    />
                                                ) : (
                                                    <div className="p-3 flex items-center gap-3">
                                                        <Paperclip size={20} className="text-blue-400" />
                                                        <div className="min-w-0">
                                                            <p className="text-sm font-medium truncate">{msg.attachment.file_name}</p>
                                                            <p className="text-[10px] opacity-60">{(msg.attachment.file_size / 1024).toFixed(1)} KB</p>
                                                        </div>
                                                    </div>
                                                )}
                                            </div>
                                        )}
                                        
                                        {msg.type === 'call' && (
                                            <div className="flex items-center gap-2 py-1 px-1 opacity-90">
                                                <div className={`p-1.5 rounded-full ${msg.content.includes('Missed') ? 'bg-red-500/20 text-red-100' : 'bg-green-500/20 text-green-100'}`}>
                                                    {msg.content.includes('video') ? <Video size={14} /> : <Phone size={14} />}
                                                </div>
                                                <div className="flex flex-col">
                                                    <span className="text-xs font-medium">{msg.content}</span>
                                                    {!isGrouped && (
                                                        <span className="text-[10px] opacity-70">
                                                            {msg.created_at ? new Date(msg.created_at).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }) : ''}
                                                        </span>
                                                    )}
                                                </div>
                                            </div>
                                        )}

                                        {msg.type === 'audio' && (
                                            <div className="flex flex-col gap-2 min-w-[200px]">
                                                <AudioPlayer 
                                                    path={msg.attachment?.storage_path || ''} 
                                                    fetchUrl={fetchSignedUrl} 
                                                />
                                                <div className="flex items-center justify-end gap-1 opacity-70">
                                                    {!isGrouped && (
                                                        <span className="text-[10px]">
                                                            {msg.created_at ? new Date(msg.created_at).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }) : 'Sending...'}
                                                        </span>
                                                    )}
                                                    {msg.sender_id === user?.id && (
                                                        <div className="text-white/80 scale-75 origin-right">
                                                            {msg.read_at ? <CheckCheck size={14} className="text-blue-300" /> : <Check size={14} />}
                                                        </div>
                                                    )}
                                                </div>
                                            </div>
                                        )}

                                        {!['call', 'audio'].includes(msg.type) && (
                                            <>
                                                {!msg.isOwn && translations[msg.id] && translations[msg.id] !== 'translating...' && !showOriginal[msg.id] ? (
                                                    <div>
                                                        <div className="flex items-center justify-between mb-1">
                                                            <div className="flex items-center gap-1.5 text-[10px] text-blue-300">
                                                                <Languages size={10} />
                                                                <span>Translated • {msg.original_language || 'detected'}</span>
                                                                <button onClick={() => setShowOriginal(prev => ({ ...prev, [msg.id]: true }))} className="underline hover:text-blue-200 ml-1">Original</button>
                                                            </div>
                                                            <button onClick={() => handleReport(msg.id, msg.content, translations[msg.id])} className="opacity-0 group-hover:opacity-100 transition-opacity text-[10px] text-gray-500 hover:text-red-400 flex items-center gap-1"><Flag size={8} /> Report</button>
                                                        </div>
                                                        <p className="break-words text-sm leading-relaxed">{translations[msg.id]}</p>
                                                    </div>
                                                ) : (
                                                    <div>
                                                        {!isGrouped && msg.sender_id !== user?.id && (
                                                            <div className="flex items-center justify-between mb-1">
                                                                <button 
                                                                    onClick={() => handleManualTranslate(msg.id, msg.content, msg.original_language)}
                                                                    className="text-[10px] text-blue-300 hover:text-blue-200 transition-colors flex items-center gap-1"
                                                                >
                                                                    <Languages size={10} />
                                                                    {translations[msg.id] ? (showOriginal[msg.id] ? "Show Translation" : "Show Original") : "Translate"}
                                                                </button>
                                                                {msg.original_language && (
                                                                    <span className="text-[8px] text-gray-500 lowercase opacity-50">Detected: {msg.original_language}</span>
                                                                )}
                                                            </div>
                                                        )}
                                                        <p className="break-words text-sm leading-relaxed">
                                                            {translations[msg.id] && !showOriginal[msg.id] && translations[msg.id] !== 'translating...' 
                                                                ? translations[msg.id] 
                                                                : msg.content}
                                                        </p>
                                                    </div>
                                                )}
                                                <div className="flex items-center justify-end gap-1 mt-1 opacity-70">
                                                    {!isGrouped && (
                                                        <span className="text-[10px] flex items-center gap-1">
                                                            {msg.is_edited && <span className="italic opacity-70">(edited)</span>}
                                                            {msg.created_at ? new Date(msg.created_at).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }) : 'Sending...'}
                                                        </span>
                                                    )}
                                                    {msg.sender_id === user?.id && (
                                                        <div className="text-white/80 scale-75 origin-right">
                                                            {msg.read_at ? (
                                                                <CheckCheck size={14} className="text-blue-300 animate-in zoom-in-50 duration-300" />
                                                            ) : (
                                                                <Check size={14} className="animate-in fade-in duration-300" />
                                                            )}
                                                        </div>
                                                    )}
                                                </div>
                                            </>
                                        )}
                                    </div>
                                </div>
                            );
                        })}
                        
                        {/* Typing Indicator */}
                        {activeConversationId && typingUsers[activeConversationId]?.length > 0 && (
                            <div className="flex justify-start items-center gap-2 mt-2 animate-in fade-in slide-in-from-left-2">
                                <div className="bg-gray-800 rounded-2xl p-3 flex gap-1 border border-gray-700 shadow-lg">
                                    <div className="w-1.5 h-1.5 bg-blue-400 rounded-full animate-bounce [animation-delay:-0.3s]"></div>
                                    <div className="w-1.5 h-1.5 bg-blue-400 rounded-full animate-bounce [animation-delay:-0.15s]"></div>
                                    <div className="w-1.5 h-1.5 bg-blue-400 rounded-full animate-bounce"></div>
                                </div>
                                <span className="text-[10px] text-gray-500 font-medium italic">
                                    {typingUsers[activeConversationId].join(', ')} {typingUsers[activeConversationId].length > 1 ? 'are' : 'is'} typing...
                                </span>
                            </div>
                        )}
                    </>
                )}

                {isPending && (
                    <div className="flex flex-col items-center justify-center p-8 bg-gray-800/50 backdrop-blur rounded-2xl my-6 border border-gray-700 shadow-xl">
                        <div className="w-16 h-16 rounded-full bg-blue-600/20 flex items-center justify-center mb-4 text-blue-400"><MoreHorizontal size={32} /></div>
                        <p className="text-gray-200 mb-6 text-center font-medium">{otherMember ? `${otherMember.profile?.full_name || otherMember.profile?.username} wants to start a conversation with you.` : 'You have been invited to this chat.'}</p>
                        <div className="flex gap-4">
                            <button onClick={handleAccept} disabled={isAccepting} className="flex-1 bg-blue-600 hover:bg-blue-700 text-white px-8 py-3 rounded-xl font-bold transition-all shadow-lg shadow-blue-900/40 disabled:opacity-50 active:scale-95">{isAccepting ? 'Accepting...' : 'Accept Chat Request'}</button>
                            <button className="px-6 py-3 text-gray-400 hover:text-white hover:bg-white/5 rounded-xl transition-all font-medium">Decline</button>
                        </div>
                    </div>
                )}
                {isWaitingForOthers && (
                    <div className="text-center p-6 bg-gray-800/30 rounded-xl my-4">
                        <Loader2 className="animate-spin text-blue-500 mx-auto mb-2" size={20} />
                        <p className="text-sm text-gray-400 italic font-medium">Waiting for acceptance...</p>
                    </div>
                )}
                <div ref={messagesEndRef} />
            </div>

            {!isAtBottom && (
                <button 
                    onClick={scrollToBottom} 
                    className="fixed right-8 bg-blue-600 text-white p-3 rounded-full shadow-2xl hover:bg-blue-700 transition-all animate-in zoom-in-0 duration-200 z-[1100] hover:scale-110 active:scale-95"
                    style={{ bottom: '120px' }}
                >
                    <ArrowDown size={20} />
                </button>
            )}

            <AnimatePresence>
                {showMediaUpload && activeConversationId && (
                    <MediaUpload conversationId={activeConversationId} onUploadComplete={handleMediaUploadComplete} onCancel={() => setShowMediaUpload(false)} />
                )}
            </AnimatePresence>



            {!isPending ? (
                <div className="fixed bottom-0 left-0 md:left-64 right-0 z-[1000] bg-gray-900 shadow-[0_-15px_40px_rgba(0,0,0,0.4)]">
                    <div className="max-w-[800px] mx-auto p-3 md:p-6 border-t border-gray-800 bg-gray-900/95 backdrop-blur-2xl pb-[max(env(safe-area-inset-bottom,16px),16px)]">
                        <form onSubmit={handleSend} className="flex flex-col gap-2 md:gap-3 max-w-full">
                            {isVoiceRecording ? (
                                <div className="flex justify-center p-3 bg-gray-800/80 backdrop-blur rounded-2xl border border-gray-700/50 animate-in slide-in-from-bottom-4 duration-300">
                                    <VoiceRecorder onSend={handleVoiceMessage} onCancel={() => setIsVoiceRecording(false)} />
                                </div>
                            ) : (
                                <div className="flex items-center gap-2 md:gap-3">
                                    <div className="flex-1 min-w-0 flex items-center gap-1 md:gap-2 bg-white/[0.03] hover:bg-white/[0.05] border border-white/[0.08] focus-within:border-blue-500/50 focus-within:bg-white/[0.06] rounded-[22px] p-1.5 px-3 md:px-4 transition-all duration-300 shadow-inner group/input">
                                        <button 
                                            type="button" 
                                            onClick={() => setShowMediaUpload(!showMediaUpload)} 
                                            className="p-2 text-gray-400 hover:text-blue-400 hover:bg-blue-400/10 rounded-full transition-all flex-shrink-0 active:scale-90"
                                        >
                                            <Plus size={22} className={`transition-transform duration-300 ${showMediaUpload ? 'rotate-45 text-blue-400' : ''}`} />
                                        </button>
                                        
                                        <div className="flex-1 relative min-w-0 flex flex-col justify-end">
                                            {editingMessageId && (
                                                <div className="absolute bottom-full left-0 mb-2 w-full flex items-center justify-between bg-blue-900/30 text-blue-200 text-xs px-3 py-1.5 rounded-lg border border-blue-500/20 backdrop-blur-md animate-in slide-in-from-bottom-2">
                                                    <span className="font-medium flex items-center gap-1.5 px-1 py-0.5">
                                                        <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M11 4H4a2 2 0 0 0-2 2v14a2 2 0 0 0 2 2h14a2 2 0 0 0 2-2v-7"></path><path d="M18.5 2.5a2.121 2.121 0 0 1 3 3L12 15l-4 1 1-4 9.5-9.5z"></path></svg>
                                                        Editing Message
                                                    </span>
                                                    <button 
                                                        type="button" 
                                                        onClick={() => { setEditingMessageId(null); setInputValue(''); }}
                                                        className="hover:bg-blue-500/20 p-1 rounded-full transition-colors"
                                                    >
                                                        <X size={14} />
                                                    </button>
                                                </div>
                                            )}
                                            {showMentions && mentionParticipants.length > 0 && (
                                                <div className="absolute bottom-full left-0 mb-4 w-full max-w-[300px] animate-in slide-in-from-bottom-2 duration-200">
                                                    <MentionSuggestions users={mentionParticipants} onSelect={handleSelectMention} />
                                                </div>
                                            )}
                                            <input 
                                                id="chat-window-input" 
                                                name="message" 
                                                type="text" 
                                                value={inputValue} 
                                                onChange={handleInputChange} 
                                                placeholder={isWaitingForOthers ? "Waiting for acceptance..." : "Type a message..."} 
                                                disabled={isWaitingForOthers} 
                                                autoComplete="off" 
                                                spellCheck={true}
                                                autoCapitalize="sentences"
                                                autoCorrect="on"
                                                className="w-full bg-transparent text-white py-2.5 md:py-3.5 px-1 md:px-2 focus:outline-none disabled:opacity-50 text-[16px] md:text-sm placeholder:text-gray-500 font-medium" 
                                            />
                                        </div>

                                        <div className="flex items-center gap-0.5 md:gap-1 flex-shrink-0">
                                            <button 
                                                type="button" 
                                                onClick={() => setIsVoiceRecording(true)} 
                                                className="p-2 text-gray-400 hover:text-blue-400 hover:bg-blue-400/10 rounded-full transition-all active:scale-90"
                                                title="Voice message"
                                            >
                                                <Mic size={20} />
                                            </button>
                                            
                                            <div className="relative md:block hidden">
                                                <button 
                                                    type="button" 
                                                    onClick={() => setShowEmojiPicker(!showEmojiPicker)} 
                                                    className={`p-2 rounded-full transition-all active:scale-90 ${showEmojiPicker ? 'text-yellow-400 bg-yellow-400/10' : 'text-gray-400 hover:text-yellow-400 hover:bg-yellow-400/10'}`}
                                                >
                                                    <Smile size={20} />
                                                </button>
                                                {showEmojiPicker && (
                                                    <div className="absolute bottom-full right-0 mb-4 p-3 bg-gray-800/95 backdrop-blur-xl border border-white/10 rounded-2xl shadow-2xl z-30 grid grid-cols-4 gap-2 animate-in zoom-in-95 duration-200 origin-bottom-right">
                                                        {emojis.map(emoji => (
                                                            <button 
                                                                key={emoji} 
                                                                type="button" 
                                                                onClick={() => { setInputValue(prev => prev + emoji); setShowEmojiPicker(false); handleInputChange({ target: { value: inputValue + emoji } } as any); }} 
                                                                className="text-xl hover:bg-white/10 p-2 rounded-xl transition-all hover:scale-110 active:scale-90"
                                                            >
                                                                {emoji}
                                                            </button>
                                                        ))}
                                                    </div>
                                                )}
                                            </div>
                                        </div>
                                    </div>
                                    
                                    <button 
                                        type="submit" 
                                        disabled={!inputValue.trim() || isWaitingForOthers} 
                                        className={`w-11 h-11 md:w-12 md:h-12 flex items-center justify-center rounded-full transition-all duration-300 shadow-xl active:scale-90 flex-shrink-0 ${
                                            inputValue.trim() && !isWaitingForOthers 
                                            ? 'bg-blue-600 text-white shadow-blue-600/30 hover:bg-blue-500 hover:-translate-y-0.5' 
                                            : 'bg-gray-800 text-gray-500 opacity-50 cursor-not-allowed'
                                        }`}
                                    >
                                        <Send size={18} className={`transition-transform duration-300 ${inputValue.trim() ? 'translate-x-0.5 -translate-y-0.5' : ''}`} />
                                    </button>
                                </div>
                            )}
                            <div className="hidden md:flex justify-between items-center px-4">
                                <p className="text-[10px] text-gray-500 font-medium flex items-center gap-1.5 opacity-60">
                                    <CheckCheck size={12} className="text-blue-500/70" /> End-to-end encrypted
                                </p>
                                {inputValue.length > 0 && (
                                    <p className="text-[10px] text-gray-600 font-bold">{inputValue.length} characters</p>
                                )}
                            </div>
                        </form>
                    </div>
                </div>
            ) : (
                <div className="fixed bottom-0 left-0 md:left-64 right-0 z-[1000] bg-gray-900 border-t border-gray-800">
                    <div className="max-w-[800px] mx-auto p-8 text-center text-gray-400 text-sm font-medium">Please accept the message request to start chatting.</div>
                </div>
            )}

            <MediaPreviewModal isOpen={previewMedia.isOpen} onClose={() => setPreviewMedia(prev => ({ ...prev, isOpen: false }))} mediaUrl={previewMedia.url} mediaType={previewMedia.type} fileName={previewMedia.fileName} isSender={previewMedia.isSender} />

            <ConfirmationModal
                isOpen={confirmModal.isOpen}
                onClose={() => setConfirmModal(prev => ({ ...prev, isOpen: false }))}
                onConfirm={async () => {
                    const { type } = confirmModal;
                    setConfirmModal(prev => ({ ...prev, isOpen: false }));
                    
                    if (type === 'message' && selectedMessages.size > 0) {
                        const toDelete = Array.from(selectedMessages);
                        const loadingToast = toDelete.length > 1 
                            ? toast.loading(`Deleting ${toDelete.length} messages...`) 
                            : undefined;
                        try {
                            for (const msgId of toDelete) {
                                await deleteMessage(msgId);
                            }
                            toast.success(
                                toDelete.length > 1 ? `${toDelete.length} messages deleted` : 'Message deleted',
                                loadingToast ? { id: loadingToast } : undefined
                            );
                            clearSelection();
                        } catch (err) {
                            toast.error('Failed to delete message(s)', loadingToast ? { id: loadingToast } : undefined);
                        }
                    } else if (type === 'clear' && activeConversationId) {
                        const loadingToast = toast.loading('Clearing history...');
                        try {
                            await clearChatHistory(activeConversationId);
                            toast.success('Chat cleared', { id: loadingToast });
                        } catch (err) {
                            toast.error('Failed to clear chat', { id: loadingToast });
                        }
                    } else if (type === 'delete_chat' && activeConversationId) {
                        const loadingToast = toast.loading('Deleting chat...');
                        try {
                            await deleteConversation(activeConversationId);
                            toast.success('Chat deleted', { id: loadingToast });
                        } catch (err) {
                            toast.error('Failed to delete chat', { id: loadingToast });
                        }
                    }
                }}
                title={
                    confirmModal.type === 'message' 
                        ? (selectedMessages.size > 1 ? `Delete ${selectedMessages.size} Messages` : 'Delete Message')
                        : confirmModal.type === 'clear' ? 'Clear History' : 'Delete Chat'
                }
                message={
                    confirmModal.type === 'message' 
                        ? (selectedMessages.size > 1 
                            ? `Are you sure you want to delete ${selectedMessages.size} selected messages? This action cannot be undone.`
                            : 'Are you sure you want to delete this message? This action cannot be undone.')
                        : confirmModal.type === 'clear' ? 'Are you sure you want to clear all messages in this chat? This only affects your view.'
                        : 'Are you sure you want to delete this conversation forever? All history will be lost.'
                }
                confirmText={
                    confirmModal.type === 'message' ? 'Delete' : 
                    confirmModal.type === 'clear' ? 'Clear' : 'Delete'
                }
                variant="danger"
            />

            {/* Forward Message Modal */}
            <ForwardMessageModal
                isOpen={forwardModal.isOpen}
                onClose={() => { setForwardModal({ isOpen: false, messages: [] }); clearSelection(); }}
                messageContent={forwardModal.messages.map(m => m.content).join('\n')}
                messageType={forwardModal.messages.length === 1 ? forwardModal.messages[0]?.type : undefined}
                onForward={async (targetConversationId: string) => {
                    try {
                        for (const msg of forwardModal.messages) {
                            const prefix = '↪️ Forwarded: ';
                            await sendMessageToConversation(targetConversationId, prefix + msg.content);
                        }
                        toast.success(`Message${forwardModal.messages.length > 1 ? 's' : ''} forwarded`);
                        clearSelection();
                    } catch (err) {
                        toast.error('Failed to forward message');
                    }
                }}
            />
        </div>
    );
};

// --- Helper Components ---



const ImageWithSignedUrl = ({ path, fetchUrl, onPreview }: { path: string, fetchUrl: (p: string) => Promise<string | null>, onPreview?: (url: string) => void }) => {
    const [url, setUrl] = useState<string | null>(null);
    useEffect(() => { fetchUrl(path).then(setUrl); }, [path, fetchUrl]);
    return <SecureImage src={url || undefined} alt="Attached" className="max-w-full h-auto cursor-pointer hover:opacity-95 transition-opacity" onClick={() => { if (url) { if (onPreview) onPreview(url); else window.open(url, '_blank'); } }} />;
};

const VideoWithSignedUrl = ({ path, fetchUrl, onPreview }: { path: string, fetchUrl: (p: string) => Promise<string | null>, onPreview?: (url: string) => void }) => {
    const [url, setUrl] = useState<string | null>(null);
    const [isLoading, setIsLoading] = useState(true);
    useEffect(() => { fetchUrl(path).then(u => { setUrl(u); if (u) setIsLoading(false); }); }, [path, fetchUrl]);
    if (isLoading) return <div className="aspect-video bg-gray-700 animate-pulse flex items-center justify-center"><Loader2 className="animate-spin text-gray-500" /></div>;
    if (!url) return <div className="p-4 text-center text-xs text-gray-500">Video failed to load</div>;
    return (
        <div className="relative group cursor-pointer" onClick={() => onPreview && onPreview(url)}>
            <video src={url} className="max-w-full rounded-lg" />
            <div className="absolute inset-0 flex items-center justify-center bg-black/20 group-hover:bg-black/40 transition-all">
                <div className="w-12 h-12 rounded-full bg-white/20 backdrop-blur-sm flex items-center justify-center text-white border border-white/30"><Maximize size={20} /></div>
            </div>
        </div>
    );
};



const SearchMessageItem = ({ msg, isOwn, query, fetchUrl, onPreviewMedia }: { msg: any, isOwn: boolean, query: string, fetchUrl: any, onPreviewMedia: (data: any) => void }) => {
    const highlight = (text: string) => {
        if (!query) return text;
        const parts = text.split(new RegExp(`(${query})`, 'gi'));
        return parts.map((part, i) => part.toLowerCase() === query.toLowerCase() ? <span key={i} className="bg-yellow-500/30 text-yellow-200 rounded-sm px-0.5">{part}</span> : part);
    };
    return (
        <div className={`flex ${isOwn ? 'justify-end' : 'justify-start'} opacity-90 hover:opacity-100 transition-opacity`}>
            <div className={`max-w-[85%] rounded-xl p-3 border ${isOwn ? 'bg-blue-600/20 border-blue-500/30' : 'bg-gray-800 border-gray-700'}`}>
                {msg.attachment && (
                    <div className="mb-2 rounded-lg overflow-hidden border border-black/20 bg-black/10 max-h-32">
                        {msg.type === 'image' ? (<ImageWithSignedUrl path={msg.attachment.storage_path} fetchUrl={fetchUrl} onPreview={(url) => onPreviewMedia({ url, type: 'image', fileName: msg.attachment.file_name, isSender: isOwn })} />) : msg.type === 'video' ? (<VideoWithSignedUrl path={msg.attachment.storage_path} fetchUrl={fetchUrl} onPreview={(url) => onPreviewMedia({ url, type: 'video', fileName: msg.attachment.file_name, isSender: isOwn })} />) : (<div className="p-2 flex items-center gap-2"><Paperclip size={14} className="text-blue-400" /><span className="text-[10px] truncate">{msg.attachment.file_name}</span></div>)}
                    </div>
                )}
                <p className="text-xs text-blue-400 font-bold mb-1">{isOwn ? 'You' : 'Matched Message'}</p>
                <p className="text-sm text-gray-200">{highlight(msg.content)}</p>
                <p className="text-[10px] text-gray-500 mt-2">{new Date(msg.created_at).toLocaleString()}</p>
