    );
};

import { useEffect, useState } from 'react';
import { Input } from '../../components/common/Input';
import { FeedNoteCard } from '../../components/dashboard/FeedNoteCard';
import { CommentModal } from '../../components/dashboard/CommentModal';
import { Search, Loader2 } from 'lucide-react';
import { supabase, safeCall } from '../../lib/supabaseSafe';
import { useAuth } from '../../context/AuthContext';

export const Feed = () => {
    const { user } = useAuth();
    const [notes, setNotes] = useState<any[]>([]);
    const [loading, setLoading] = useState(true);
    const [searchTerm, setSearchTerm] = useState('');
    const [activeNote, setActiveNote] = useState<any | null>(null);

    const fetchFeed = async () => {
        if (!user) return;
        setLoading(true);
        
        const result = await safeCall(
            `feed-${user.id}-${searchTerm}`,
            async () => {
                // Fetch public notes
                const query = supabase
                    .from('notes')
                    .select(`
                        *,
                        owner:profiles!owner_id (username, email, avatar_url, plan_tier, is_verified)
                    `)
                    .eq('is_private', false)
                    .order('created_at', { ascending: false });

                if (searchTerm) {
                    query.ilike('title', `%${searchTerm}%`);
                }

                const { data: notesData, error } = await query;
                if (error) throw error;

                if (notesData) {
                    // Fetch likes and comments counts for each note
                    const enhancedNotes = await Promise.all(notesData.map(async (note) => {
                        const [likesCount, commentsCount, userLike] = await Promise.all([
                            supabase.rpc('get_like_count', { p_note_id: note.id }),
                            supabase.rpc('get_comment_count', { p_note_id: note.id }),
                            supabase.from('likes').select('id').eq('note_id', note.id).eq('user_id', user.id).maybeSingle()
                        ]);

                        return {
                            ...note,
                            likes_count: likesCount.data || 0,
                            comments_count: commentsCount.data || 0,
                            user_has_liked: !!userLike.data
                        };
                    }));

                    return enhancedNotes;
                }
                return [];
            },
            { minDelay: 1000, fallback: [] }
        );

        setNotes(result || []);
        setLoading(false);
    };

    useEffect(() => {
        const timeoutId = setTimeout(() => {
            fetchFeed();
        }, 500);

        // Setup Realtime Subscriptions for counts
        // Use debounce to prevent excessive refetching from global events
        let debounceTimer: ReturnType<typeof setTimeout> | null = null;
        const debouncedRefetch = () => {
            if (debounceTimer) clearTimeout(debounceTimer);
            debounceTimer = setTimeout(() => fetchFeed(), 2000);
        };

        const commentChannel = supabase
            .channel('public-comments')
            .on(
                'postgres_changes',
                { event: '*', schema: 'public', table: 'comments' },
                () => debouncedRefetch()
            )
            .subscribe();

        const likeChannel = supabase
            .channel('public-likes')
            .on(
                'postgres_changes',
                { event: '*', schema: 'public', table: 'likes' },
                () => debouncedRefetch()
            )
            .subscribe();

        return () => {
            clearTimeout(timeoutId);
            if (debounceTimer) clearTimeout(debounceTimer);
            supabase.removeChannel(commentChannel);
            supabase.removeChannel(likeChannel);
        };
    }, [user, searchTerm]);

    return (
        <div className="space-y-6 max-w-4xl mx-auto">
            <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
                <div className="space-y-1">
                    <h1 className="text-3xl font-bold">Community Feed</h1>
                    <p className="text-gray-400">Discover public notes from other users</p>
                </div>
                <div className="w-full md:w-72">
                    <Input
                        id="feed-search"
                        name="feedSearch"
                        icon={Search}
                        placeholder="Search public notes..."
                        className="bg-[#121212]"
                        value={searchTerm}
                        onChange={(e) => setSearchTerm(e.target.value)}
                    />
                </div>
            </div>

            {loading ? (
                <div className="flex items-center justify-center py-20">
                    <Loader2 className="animate-spin text-primary" size={32} />
                </div>
            ) : notes.length === 0 ? (
                <div className="text-center py-20 space-y-3">
                    <div className="text-gray-500">No public notes found yet.</div>
                    <div className="text-sm text-gray-600">Be the first to share a note publicly!</div>
                </div>
            ) : (
                <div className="space-y-4">
                    {notes.map((note) => (
                        <FeedNoteCard
                            key={note.id}
                            note={note}
                            onCommentClick={setActiveNote}
                        />
                    ))}
                </div>
            )}

            <CommentModal
                isOpen={!!activeNote}
                onClose={() => setActiveNote(null)}
                note={activeNote}
            />
        </div>
    );
};

import { useState, useEffect } from 'react';
import { Card } from '../../components/common/Card';
import { Input } from '../../components/common/Input';
import { Search as SearchIcon, User, FileText, Loader2 } from 'lucide-react';
import { supabase } from '../../lib/supabase';
import { useNavigate, useSearchParams } from 'react-router-dom';
import { useAuth } from '../../context/AuthContext';
import SecureImage from '../../components/common/SecureImage';
import { ViewNoteModal } from '../../components/dashboard/ViewNoteModal';

interface UserResult {
    id: string;
    username: string;
    email: string;
    avatar_url?: string;
    full_name?: string;
}

interface NoteResult {
    id: string;
    title: string;
    content: string;
    created_at: string;
    owner_id: string;
    is_private: boolean;
    owner: {
        username: string;
        avatar_url?: string;
    };
}

type TabType = 'all' | 'users' | 'notes';

export const Search = () => {
    const { user } = useAuth();
    const navigate = useNavigate();
    const [searchParams] = useSearchParams();
    const initialQuery = searchParams.get('q') || '';
    
    const [searchTerm, setSearchTerm] = useState(initialQuery);
    const [activeTab, setActiveTab] = useState<TabType>('all');
    const [users, setUsers] = useState<UserResult[]>([]);
    const [notes, setNotes] = useState<NoteResult[]>([]);
    const [loading, setLoading] = useState(false);
    const [hasSearched, setHasSearched] = useState(false);
    const [viewingNote, setViewingNote] = useState<NoteResult | null>(null);

    // Initial search from URL
    useEffect(() => {
        if (initialQuery) {
            handleSearch(initialQuery);
        }
    }, []);

    // Realtime search effect
    useEffect(() => {
        const timeoutId = setTimeout(() => {
            if (searchTerm.trim()) {
                handleSearch();
            } else {
                setUsers([]);
                setNotes([]);
                setHasSearched(false);
            }
        }, 500);

        return () => clearTimeout(timeoutId);
    }, [searchTerm, activeTab]);

    const handleSearch = async (explicitQuery?: string) => {
        const queryToUse = explicitQuery || searchTerm;
        if (!queryToUse.trim()) return;

        setLoading(true);
        setHasSearched(true);

        try {
            // 1. Search users
            const { data: usersData, error: usersError } = await supabase
                .from('profiles')
                .select('id, username, email, avatar_url, full_name')
                .or(`username.ilike.%${queryToUse}%,full_name.ilike.%${queryToUse}%`)
                .limit(20);

            if (usersError) throw usersError;
            setUsers(usersData || []);

            // 2. Search notes (Relies on RLS to filter Owner + Public + Shared)
            const notesQuery = supabase
                .from('notes')
                .select(`
                    id, title, content, created_at, owner_id, is_private,
                    owner:profiles!owner_id (username, avatar_url)
                `)
                .or(`title.ilike.%${queryToUse}%,content.ilike.%${queryToUse}%`)
                .order('created_at', { ascending: false })
                .limit(20);

            const { data: notesData, error: notesError } = await notesQuery;

            if (notesError) throw notesError;
            setNotes(notesData as any || []);

        } catch (error) {
            console.error('Search error:', error);
        } finally {
            setLoading(false);
        }
    };

    const filteredUsers = activeTab === 'notes' ? [] : users;
    const filteredNotes = activeTab === 'users' ? [] : notes;

    const getInitials = (name: string) => {
        if (!name) return 'U';
        return name
            .split(' ')
            .map(n => n?.[0] || '')
            .join('')
            .substring(0, 2)
            .toUpperCase();
    };

    return (
        <div className="space-y-6 max-w-4xl mx-auto">
            <div className="space-y-1">
                <h1 className="text-3xl font-bold">Search</h1>
                <p className="text-gray-400">Find users and accessible notes (yours, public, or shared)</p>
            </div>

            <Card variant="glass" className="p-4">
                <div className="flex gap-3">
                    <div className="flex-1">
                        <Input
                            id="global-search"
                            name="search"
                            icon={SearchIcon}
                            value={searchTerm}
                            onChange={(e) => setSearchTerm(e.target.value)}
                            placeholder="Search for users or notes..."
                            className="bg-white/5"
                            aria-label="Search for users or accessible notes"
                        />
                    </div>
                    {loading && (
                        <div className="flex items-center px-3">
                            <Loader2 size={18} className="animate-spin text-primary" />
                        </div>
                    )}
                </div>
            </Card>

            {hasSearched && (
                <div className="flex gap-2 border-b border-white/10 pb-2 flex-wrap">
                    {(['all', 'users', 'notes'] as TabType[]).map((tab) => (
                        <button
                            key={tab}
                            onClick={() => setActiveTab(tab)}
                            className={`px-4 py-2 text-sm font-medium rounded-lg transition-colors ${activeTab === tab
                                ? 'bg-primary/20 text-primary border border-primary/30'
                                : 'text-gray-400 hover:text-white hover:bg-white/5'
                                }`}
                        >
                            {tab === 'all' && `All (${users.length + notes.length})`}
                            {tab === 'users' && `Users (${users.length})`}
                            {tab === 'notes' && `Notes (${notes.length})`}
                        </button>
                    ))}
                </div>
            )}

            {loading ? (
                <div className="flex items-center justify-center py-20">
                    <Loader2 className="animate-spin text-primary" size={32} />
                </div>
            ) : hasSearched ? (
                <div className="space-y-6">
                    {filteredUsers.length > 0 && (
                        <div>
                            <h2 className="text-lg font-semibold mb-3 flex items-center gap-2">
                                <User size={18} className="text-primary" />
                                Users
                            </h2>
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                                {filteredUsers?.map((u) => (
                                    <Card
                                        key={u.id}
                                        hoverEffect
                                        className="p-4 flex items-center gap-3 cursor-pointer"
                                        onClick={() => navigate(`/dashboard/chat?email=${u.email}`)}
                                    >
                                        {u.avatar_url ? (
                                            <SecureImage
                                                src={u.avatar_url}
                                                alt={u.username}
                                                className="w-12 h-12 rounded-full object-cover"
                                                fallbackType="profile"
                                            />
                                        ) : (
                                            <div className="w-12 h-12 rounded-full bg-gradient-to-tr from-blue-500 to-purple-500 flex items-center justify-center text-sm font-bold text-white">
                                                {getInitials(u.full_name || u.username || u.email)}
                                            </div>
                                        )}
                                        <div className="flex-1 min-w-0">
                                            <div className="font-medium text-white truncate">
                                                {u.full_name || u.username}
                                            </div>
                                            <div className="text-sm text-gray-400 truncate">
                                                @{u.username}
                                            </div>
                                        </div>
                                    </Card>
                                ))}
                            </div>
                            {filteredUsers.length === 20 && (
                                <p className="text-xs text-center text-gray-500 mt-2">Showing top 20 users</p>
                            )}
                        </div>
                    )}

                    {filteredNotes.length > 0 && (
                        <div>
                            <h2 className="text-lg font-semibold mb-3 flex items-center gap-2">
                                <FileText size={18} className="text-primary" />
                                Notes
                            </h2>
                            <div className="space-y-3">
                                {filteredNotes?.map((note) => (
                                    <Card
                                        key={note.id}
                                        hoverEffect
                                        className="p-4 cursor-pointer"
                                        onClick={() => setViewingNote(note)}
                                    >
                                        <div className="flex items-start gap-3">
                                            {note.owner?.avatar_url ? (
                                                <SecureImage
                                                    src={note.owner.avatar_url}
                                                    alt={note.owner.username}
                                                    className="w-10 h-10 rounded-full object-cover"
                                                    fallbackType="profile"
                                                />
                                            ) : (
                                                <div className="w-10 h-10 rounded-full bg-gradient-to-tr from-blue-500 to-purple-500 flex items-center justify-center text-xs font-bold text-white">
                                                    {getInitials(note.owner?.username || 'U')}
                                                </div>
                                            )}
                                            <div className="flex-1 min-w-0">
                                                <div className="flex items-center gap-2 mb-1">
                                                    <span className="text-sm text-gray-400">
                                                        @{note.owner?.username || 'Unknown'}
                                                    </span>
                                                    <span className="text-xs text-gray-500">
                                                        {new Date(note.created_at).toLocaleDateString()}
                                                    </span>
                                                    {!note.is_private && (
                                                        <span className="text-[10px] bg-primary/10 text-primary px-1.5 py-0.5 rounded border border-primary/20">Public</span>
                                                    )}
                                                </div>
                                                <h3 className="font-semibold text-white mb-1 group-hover:text-primary transition-colors">
                                                    {note.title || 'Untitled'}
                                                </h3>
                                                <p className="text-sm text-gray-400 line-clamp-2">
                                                    {note.content || 'No content...'}
                                                </p>
                                            </div>
                                        </div>
                                    </Card>
                                ))}
                            </div>
                        </div>
                    )}

                    {filteredUsers.length === 0 && filteredNotes.length === 0 && (
                        <div className="text-center py-20">
                            <div className="text-gray-500 mb-2">No results found for "{searchTerm}"</div>
                            <div className="text-sm text-gray-600">Try a different search term</div>
                        </div>
                    )}
                </div>
            ) : (
                <div className="text-center py-20">
                    <SearchIcon size={48} className="mx-auto text-gray-600 mb-4" />
                    <div className="text-gray-500">Enter a search term to find users and notes</div>
                </div>
            )}

            <ViewNoteModal
                isOpen={!!viewingNote}
                onClose={() => setViewingNote(null)}
                note={viewingNote as any}
            />
        </div>
    );
};

import React, { useState, useEffect } from 'react';
import { useWallet } from '../../hooks/useWallet';
import { 
    ArrowDownLeft, 
    ArrowUpRight, 
    Clock, 
    CheckCircle2, 
    XCircle, 
    ChevronLeft, 
    ChevronRight,
    Search,
    FileText,
    ArrowRight
} from 'lucide-react';
import { formatCurrency } from '../../lib/CurrencyFormatter';
import walletApi from '../../api/walletApi';
import toast from 'react-hot-toast';
import { Button } from '../../components/common/Button';
import { cn } from '../../utils/cn';

interface TransactionDetailModalProps {
    tx: any;
    onClose: () => void;
}

const TransactionDetailModal: React.FC<TransactionDetailModalProps> = ({ tx, onClose }) => {
    return (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
            <div className="absolute inset-0 bg-black/80 backdrop-blur-md" onClick={onClose} />
            <div className="relative bg-[#1a1a1a] border border-white/10 rounded-3xl w-full max-w-md overflow-hidden animate-in fade-in zoom-in duration-300">
                <div className="p-6 text-center border-b border-white/5 bg-gradient-to-b from-white/5 to-transparent">
                    <div className={cn(
                        "w-16 h-16 rounded-full mx-auto flex items-center justify-center mb-4 text-2xl font-bold",
                        tx.type.includes('IN') || tx.type === 'DEPOSIT' ? "bg-green-500/20 text-green-400" : "bg-red-500/20 text-red-400"
                    )}>
                        {tx.type.includes('IN') || tx.type === 'DEPOSIT' ? <ArrowDownLeft size={32} /> : <ArrowUpRight size={32} />}
                    </div>
                    <h2 className="text-xl font-bold">{tx.display_label || tx.type.replace(/_/g, ' ')}</h2>
                    <p className="text-gray-400 text-sm mt-1">{new Date(tx.created_at).toLocaleString()}</p>
                </div>

                <div className="p-6 space-y-6">
                    <div className="flex justify-between items-center text-sm">
                        <span className="text-gray-500">Status</span>
                        <div className={cn(
                            "flex items-center gap-1.5 px-3 py-1 rounded-full font-bold text-[10px] uppercase tracking-wider border",
                            tx.status === 'COMPLETED' || tx.status === 'confirmed' ? "text-green-500 bg-green-500/10 border-green-500/20" : 
                            tx.status === 'FAILED' ? "text-rose-500 bg-rose-500/10 border-rose-500/20" : "text-amber-500 bg-amber-500/10 border-amber-500/20"
                        )}>
                            {tx.status === 'COMPLETED' || tx.status === 'confirmed' ? <CheckCircle2 size={12} /> : 
                             tx.status === 'FAILED' ? <XCircle size={12} /> : <Clock size={12} className="animate-pulse" />}
                            {tx.status}
                        </div>
                    </div>

                    <div className="flex justify-between items-center">
                        <span className="text-gray-500 text-sm">Amount</span>
                        <span className={cn(
                            "text-lg font-bold",
                            tx.type.includes('IN') || tx.type === 'DEPOSIT' ? "text-green-400" : "text-white"
                        )}>
                            {tx.type.includes('IN') || tx.type === 'DEPOSIT' ? '+' : '-'} {formatCurrency(tx.amount, tx.currency)}
                        </span>
                    </div>

                    {tx.exchange_rate && (
                        <div className="flex justify-between items-center text-sm">
                            <span className="text-gray-500">Exchange Rate</span>
                            <span className="text-gray-300">1 {tx.currency} = {tx.exchange_rate} {tx.metadata?.to_currency || 'USD'}</span>
                        </div>
                    )}

                    {tx.fee > 0 && (
                        <div className="flex justify-between items-center text-sm">
                            <span className="text-gray-500">Fee</span>
                            <span className="text-gray-300">{formatCurrency(tx.fee, tx.currency)}</span>
                        </div>
                    )}

                    <div className="pt-4 border-t border-white/5 space-y-4">
                        <div className="flex justify-between items-start text-sm">
                            <span className="text-gray-500">From</span>
                            <span className="text-gray-300 text-right max-w-[200px] truncate">
                                {tx.metadata?.sender_address || tx.provider || 'Internal Wallet'}
                            </span>
                        </div>
                        <div className="flex justify-between items-start text-sm">
                            <span className="text-gray-500">To</span>
                            <span className="text-gray-300 text-right max-w-[200px] truncate">
                                {tx.metadata?.receiver_address || 'NoteStandard Wallet'}
                            </span>
                        </div>
                    </div>

                    <div className="pt-4 space-y-3">
                        {tx.status === 'COMPLETED' && (
                            <Button 
                                className="w-full justify-center gap-2"
                                onClick={() => {
                                    toast.promise(walletApi.downloadInvoice(tx.id), {
                                        loading: 'Generating Receipt...',
                                        success: 'Receipt downloaded!',
                                        error: 'Failed to download receipt'
                                    });
                                }}
                            >
                                <FileText size={18} /> Download Receipt
                            </Button>
                        )}
                        <Button variant="ghost" className="w-full text-gray-500 hover:text-white" onClick={onClose}>
                            Close
                        </Button>
                    </div>
                </div>
            </div>
        </div>
    );
};

export const Transactions: React.FC = () => {
    const { refresh } = useWallet();
    const [transactions, setTransactions] = useState<any[]>([]);
    const [loading, setLoading] = useState(true);
    const [currencyFilter, setCurrencyFilter] = useState('ALL');
    const [statusFilter, setStatusFilter] = useState('ALL');
    const [typeFilter, setTypeFilter] = useState('ALL');
    const [searchTerm, setSearchTerm] = useState('');
    const [currentPage, setCurrentPage] = useState(1);
    const [totalCount, setTotalCount] = useState(0);
    const [, setHasMore] = useState(false);
    const [selectedTx, setSelectedTx] = useState<any>(null);
    const itemsPerPage = 20;

    const fetchTransactions = async (page: number) => {
        setLoading(true);
        try {
            const params: any = { page, limit: itemsPerPage };
            if (currencyFilter !== 'ALL') params.currency = currencyFilter;
            if (statusFilter !== 'ALL') params.status = statusFilter;
            if (typeFilter !== 'ALL') params.type = typeFilter;
            if (searchTerm) params.search = searchTerm;
            
            const data = await walletApi.getTransactions(params);
            setTransactions(data?.transactions || []);
            setTotalCount(data?.pagination?.totalCount || data?.total || 0);
            setHasMore(data?.pagination?.hasMore || false);
        } catch (err) {
            console.error('Failed to fetch transactions', err);
            toast.error('Failed to load transactions');
        } finally {
            setLoading(false);
        }
    };

    // Re-fetch when page or any filter changes
    useEffect(() => {
        fetchTransactions(currentPage);
    }, [currentPage, currencyFilter, statusFilter, typeFilter, searchTerm]);

    const safeTransactions = Array.isArray(transactions) ? transactions : [];
    
    // Currencies extracted from real data plus common defaults for the dropdown
    const currencies = ['ALL', 'USD', 'NGN', 'EUR', 'GBP', 'BTC', 'ETH', 'USDT'];
    const statuses = ['ALL', 'COMPLETED', 'PENDING', 'FAILED'];
    const types = ['ALL', 'DEPOSIT', 'WITHDRAWAL', 'TRANSFER', 'SWAP'];

    const totalPages = Math.ceil(totalCount / itemsPerPage);

    // We no longer filter locally, the backend handles it.
    const filteredTransactions = safeTransactions;

    const getStatusStyles = (status: string) => {
        const s = status.toUpperCase();
        if (s === 'COMPLETED' || s === 'CONFIRMED') return 'text-green-500 bg-green-500/10 border-green-500/20';
        if (s === 'FAILED') return 'text-rose-500 bg-rose-500/10 border-rose-500/20';
        return 'text-amber-500 bg-amber-500/10 border-amber-500/20';
    };

    const getStatusIcon = (status: string) => {
        const s = status.toUpperCase();
        if (s === 'COMPLETED' || s === 'CONFIRMED') return <CheckCircle2 size={12} />;
        if (s === 'FAILED') return <XCircle size={12} />;
        return <Clock size={12} className="animate-pulse" />;
    };

    return (
        <div className="min-h-screen bg-[#0a0a0a] text-white overflow-hidden flex flex-col w-full max-w-full">
            <div className="flex flex-col gap-6 w-full max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8 h-full overflow-hidden">
                
                {/* Header */}
                <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
                    <div>
                        <h1 className="text-3xl font-black tracking-tight text-white flex items-center gap-3">
                             Transactions
                        </h1>
                        <p className="text-gray-400 mt-1">Detailed history of all your platform activities</p>
                    </div>
                    <Button onClick={refresh} className="bg-white/5 border-white/10 hover:bg-white/10" variant="outline">
                        Refresh
                    </Button>
                </div>

                {/* Filters Row */}
                <div className="flex flex-wrap items-center gap-3">
                    <div className="relative group min-w-[200px]">
                        <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400 group-focus-within:text-white transition-colors" size={16} />
                        <input 
                            id="transaction-search"
                            name="transaction-search"
                            type="text" 
                            placeholder="Search by ID or Reference..."
                            value={searchTerm}
                            onChange={(e) => setSearchTerm(e.target.value)}
                            className="w-full bg-white/5 border border-white/10 rounded-xl py-2 pl-10 pr-4 outline-none focus:ring-2 focus:ring-white/10 transition-all text-sm"
                        />
                    </div>
                    
                    <div className="flex items-center gap-2 bg-white/5 border border-white/10 rounded-xl p-1">
                        {statuses.map(s => (
                            <button
                                key={s}
                                onClick={() => setStatusFilter(s)}
                                className={cn(
                                    "px-3 py-1 rounded-lg text-xs font-semibold transition-all",
                                    statusFilter === s ? "bg-white text-black shadow-lg" : "text-gray-400 hover:text-white"
                                )}
                            >
                                {s}
                            </button>
                        ))}
                    </div>

                    <div className="flex items-center gap-2">
                        <select 
                            id="currency-filter"
                            name="currency"
                            value={currencyFilter}
                            onChange={(e) => setCurrencyFilter(e.target.value)}
                            className="bg-white/5 border border-white/10 rounded-xl px-4 py-2 text-xs outline-none focus:ring-2 focus:ring-white/10 appearance-none"
                        >
                            {currencies.map(c => <option key={c} value={c} className="bg-black">{c} Currencies</option>)}
                        </select>

                        <select 
                            id="type-filter"
                            name="type"
                            value={typeFilter}
                            onChange={(e) => setTypeFilter(e.target.value)}
                            className="bg-white/5 border border-white/10 rounded-xl px-4 py-2 text-xs outline-none focus:ring-2 focus:ring-white/10 appearance-none"
                        >
                            {types.map(t => <option key={t} value={t} className="bg-black">{t}</option>)}
                        </select>
                    </div>
                </div>

                {/* Table Section */}
                <div className="bg-[#111] border border-white/5 rounded-3xl overflow-hidden flex flex-col flex-1 min-h-0 min-w-0">
                    <div className="overflow-x-auto overflow-y-auto flex-1 h-full min-w-0 overscroll-x-none">
                        <table className="w-full text-left border-collapse min-w-[800px] table-fixed">
                            <thead>
                                <tr className="border-b border-white/5 text-[10px] uppercase font-bold text-gray-500 tracking-widest">
                                    <th className="py-5 px-6 w-1/4">Type & Description</th>
                                    <th className="py-5 px-4 w-1/6">From → To</th>
                                    <th className="py-5 px-4 w-1/6 text-right">Amount</th>
                                    <th className="py-5 px-4 w-1/6 text-right">Rate / Fee</th>
                                    <th className="py-5 px-4 w-1/6 text-center">Status</th>
                                    <th className="py-5 px-6 w-1/6 text-right">Time</th>
                                </tr>
                            </thead>
                            <tbody className="divide-y divide-white/5">
                                {loading ? (
                                    // Loading skeleton rows
                                    Array.from({ length: 5 }).map((_, i) => (
                                        <tr key={`skeleton-${i}`} className="animate-pulse">
                                            <td className="py-5 px-6"><div className="flex items-center gap-4"><div className="w-10 h-10 rounded-full bg-white/5" /><div className="space-y-2"><div className="h-3 w-24 bg-white/5 rounded" /><div className="h-2 w-16 bg-white/5 rounded" /></div></div></td>
                                            <td className="py-5 px-4"><div className="h-3 w-20 bg-white/5 rounded" /></td>
                                            <td className="py-5 px-4 text-right"><div className="h-3 w-16 bg-white/5 rounded ml-auto" /></td>
                                            <td className="py-5 px-4 text-right"><div className="h-3 w-12 bg-white/5 rounded ml-auto" /></td>
                                            <td className="py-5 px-4 text-center"><div className="h-5 w-20 bg-white/5 rounded-full mx-auto" /></td>
                                            <td className="py-5 px-6 text-right"><div className="h-3 w-16 bg-white/5 rounded ml-auto" /></td>
                                        </tr>
                                    ))
                                ) : (
                                    filteredTransactions.map((tx) => (
                                    <tr 
                                        key={tx.id} 
                                        className="hover:bg-white/[0.02] cursor-pointer transition-colors group"
                                        onClick={() => setSelectedTx(tx)}
                                    >
                                        <td className="py-5 px-6 truncate">
                                            <div className="flex items-center gap-4 min-w-0">
                                                <div className={cn(
                                                    "w-10 h-10 rounded-full flex items-center justify-center shrink-0",
                                                    tx.type.includes('IN') || tx.type === 'DEPOSIT' ? "bg-green-500/10 text-green-400" : 
                                                    tx.type === 'SWAP' ? "bg-purple-500/10 text-purple-400" : "bg-red-500/10 text-red-400"
                                                )}>
                                                    {tx.type.includes('IN') || tx.type === 'DEPOSIT' ? <ArrowDownLeft size={18} /> : 
                                                     tx.type.includes('SWAP') ? <ArrowRight size={18} /> : <ArrowUpRight size={18} />}
                                                </div>
                                                <div className="min-w-0">
                                                    <p className="font-bold text-sm truncate">{tx.display_label || tx.type.replace(/_/g, ' ')}</p>
                                                    <p className="text-[10px] text-gray-500 font-mono">#{tx.id.substring(0, 12)}</p>
                                                </div>
                                            </div>
                                        </td>
                                        <td className="py-5 px-4">
                                            <div className="flex items-center gap-2 text-xs font-medium text-gray-400">
                                                <span className="bg-white/5 px-2 py-0.5 rounded uppercase">{tx.currency || 'USD'}</span>
                                                <ArrowRight size={12} className="text-gray-600" />
                                                <span className="bg-white/5 px-2 py-0.5 rounded uppercase italic">{tx.metadata?.to_currency || tx.currency || 'USD'}</span>
                                            </div>
                                        </td>
                                        <td className={cn(
                                            "py-5 px-4 text-right font-black text-sm",
                                            tx.type.includes('IN') || tx.type === 'DEPOSIT' ? "text-green-400" : "text-white"
                                        )}>
                                            {tx.type.includes('IN') || tx.type === 'DEPOSIT' ? '+' : '-'} {formatCurrency(tx.amount, tx.currency)}
                                        </td>
                                        <td className="py-5 px-4 text-right">
                                            <div className="space-y-1">
                                                {tx.exchange_rate ? (
                                                    <p className="text-[11px] font-mono text-gray-400">{tx.exchange_rate?.toFixed(4)}</p>
                                                ) : <p className="text-[11px] text-gray-600">—</p>}
                                                <p className="text-[10px] text-rose-500/80">{tx.fee > 0 ? `Fee: ${formatCurrency(tx.fee, tx.currency)}` : ''}</p>
                                            </div>
                                        </td>
                                        <td className="py-5 px-4 text-center">
                                            <div className={cn(
                                                "inline-flex items-center justify-center gap-1.5 px-3 py-1 rounded-full text-[10px] font-bold uppercase tracking-wider border whitespace-nowrap",
                                                getStatusStyles(tx.status)
                                            )}>
                                                {getStatusIcon(tx.status)}
                                                {tx.status}
                                            </div>
                                        </td>
                                        <td className="py-5 px-6 text-right">
                                            <div className="space-y-0.5">
                                                <p className="text-xs font-bold">{new Date(tx.created_at).toLocaleDateString()}</p>
                                                <p className="text-[10px] text-gray-500">{new Date(tx.created_at).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</p>
                                            </div>
                                        </td>
                                    </tr>
                                    ))
                                )}
                            </tbody>
                        </table>
                    </div>

                    {/* Pagination */}
                    {totalPages > 1 && (
                        <div className="p-6 border-t border-white/5 flex items-center justify-between">
                            <p className="text-xs text-gray-500">
                                Showing <span className="text-white">{(currentPage - 1) * itemsPerPage + 1}</span> to <span className="text-white">{Math.min(currentPage * itemsPerPage, totalCount)}</span> of <span className="text-white">{totalCount}</span> transactions
                            </p>
                            <div className="flex items-center gap-2">
                                <Button 
                                    size="sm" 
                                    variant="outline" 
                                    className="p-2 border-white/5 hover:bg-white/5 disabled:opacity-30"
                                    onClick={() => setCurrentPage(p => Math.max(1, p - 1))}
                                    disabled={currentPage === 1}
                                >
                                    <ChevronLeft size={16} />
                                </Button>
                                <div className="flex items-center gap-1">
                                    {/* Simple pagination logic for 100+ transactions */}
                                    <span className="text-xs text-gray-400 px-2 font-mono">
                                        Page {currentPage} of {totalPages || 1}
                                    </span>
                                </div>
                                <Button 
                                    size="sm" 
                                    variant="outline" 
                                    className="p-2 border-white/5 hover:bg-white/5 disabled:opacity-30"
                                    onClick={() => setCurrentPage(p => Math.min(totalPages, p + 1))}
                                    disabled={currentPage === totalPages}
                                >
                                    <ChevronRight size={16} />
                                </Button>
                            </div>
                        </div>
                    )}

                    {safeTransactions.length === 0 && !loading && (
                        <div className="flex-1 flex flex-col items-center justify-center py-20 bg-white/[0.01]">
                            <div className="w-16 h-16 rounded-full bg-white/5 flex items-center justify-center mb-4">
                                <Search size={24} className="text-gray-500" />
                            </div>
                            <h3 className="text-lg font-bold">No transactions found</h3>
                            <p className="text-gray-500 text-sm mt-1 max-w-xs text-center">Your transaction history is empty.</p>
                        </div>
                    )}
                </div>
            </div>

            {selectedTx && <TransactionDetailModal tx={selectedTx} onClose={() => setSelectedTx(null)} />}
        </div>
    );
};

